'use client';

import React, { useState, useMemo, useEffect } from 'react';
import { useRouter, useParams } from 'next/navigation';
import {
    ArrowLeft, Printer, ReceiptText, Clock, Users, History,
    PlusCircle, Minus, Plus, CreditCard, Banknote, QrCode,
    CheckCircle, Share, Info, Ticket, UtensilsCrossed, Loader2, Search, Combine
} from 'lucide-react';
import { useFormatters } from '@/hooks/useFormatters';
import { cn } from '@/lib/utils';
import Card from '@/components/ui/Card';
import { MesaWithActiveSession, abrirMesa, addSessionItem, fecharMesaSessao, confirmarItensMesa, separarMesa, desagruparTodas } from '@/lib/services/mesas';
import { printOrder } from '@/lib/print';
import { useAuth } from '@/contexts/AuthContext';
import { useProductsCache, useCategoriesCache, useTableDetailCache, type Product, type Category } from '@/hooks/useDataCache';
import { supabase } from '@/lib/supabase';



export default function MesaDetailsPage() {
    const router = useRouter();
    const params = useParams() as { id: string };
    const { formatCurrency } = useFormatters();

    const { user, userSettings } = useAuth();
    const { table: mesa, loading: loadingMesa, refetch: reloadMesa } = useTableDetailCache(params.id);
    const { products, loading: loadingProducts } = useProductsCache();
    const { categories, loading: loadingCategories } = useCategoriesCache();
    
    const [addingItem, setAddingItem] = useState(false);
    const [closingMesa, setClosingMesa] = useState(false);
    const [isConfirming, setIsConfirming] = useState(false);
    const [groupedCount, setGroupedCount] = useState(0);

    // Abrir sessão state
    const [nomeGarcom, setNomeGarcom] = useState('');

    const [view, setView] = useState<'detalhes' | 'pagamento'>('detalhes');
    const [activeCategory, setActiveCategory] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');

    const loading = loadingMesa && !mesa;

    useEffect(() => {
        if (categories.length > 0 && !activeCategory) {
            setActiveCategory(categories[0].id);
        }
    }, [categories, activeCategory]);

    useEffect(() => {
        if (mesa?.active_session?.status === 'fechando') {
            setView('pagamento');
        }
    }, [mesa?.active_session?.status]);

    useEffect(() => {
        const checkGrouped = async () => {
            if (mesa?.active_session) {
                const tableNumStr = String(String(mesa.numero_mesa).padStart(2, '0'));
                const groupedStr = `[Unida c/ Mesa ${tableNumStr}]`;
                const { count } = await supabase
                    .from('mesa_sessions')
                    .select('*', { count: 'exact', head: true })
                    .eq('garcom', groupedStr)
                    .is('closed_at', null);
                
                setGroupedCount(count || 0);
            }
        };
        checkGrouped();
    }, [mesa]);



    const filteredProducts = useMemo(() => {
        const normalize = (text: string) =>
            text.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase();

        const searchNormalized = normalize(searchTerm);

        return products.filter(p => {
            const productNameNormalized = normalize(p.name);
            const matchesSearch = productNameNormalized.includes(searchNormalized);

            // Se houver busca, ignoramos o filtro de categoria (busca global)
            if (searchTerm.trim() !== '') {
                return matchesSearch;
            }

            // Se não houver busca, filtramos por categoria
            return p.category_id === activeCategory;
        });
    }, [activeCategory, products, searchTerm]);

    // Payment state
    const [splitCount, setSplitCount] = useState(1);
    const [selectedPayment, setSelectedPayment] = useState<string | null>(null);
    const [valorRecebido, setValorRecebido] = useState<number | ''>('');

    // Taxa de serviço configurável (agora vem do userSettings)
    const taxaServicoEnabled = userSettings?.taxa_servico_enabled ?? false;
    const taxaServicoPercent = userSettings?.taxa_servico_percent ?? 10;

    if (loading) {
        return (
            <div className="max-w-[1200px] mx-auto flex items-center justify-center h-64 text-text-muted">
                <Loader2 className="w-8 h-8 animate-spin" />
            </div>
        );
    }

    if (!mesa) {
        return (
            <div className="max-w-[1400px] mx-auto">
                <div className="flex items-center gap-4 mb-6">
                    <button
                        className="w-10 h-10 flex items-center justify-center rounded-full bg-bg-tertiary text-text-secondary hover:bg-primary hover:text-white transition-all cursor-pointer"
                        onClick={() => router.push('/mesas')}
                    >
                        <ArrowLeft size={20} />
                    </button>
                    <h1 className="text-2xl font-bold">Mesa não encontrada</h1>
                </div>
            </div>
        );
    }

    const activeSession = mesa.active_session;
    const status = activeSession?.status || 'livre';

    const isMerged = activeSession && activeSession.garcom?.startsWith('[Unida c/');

    if (isMerged && activeSession) {
        return (
            <div className="max-w-[1400px] mx-auto p-4 md:p-6 animate-fadeIn">
                <div className="flex items-center gap-4 mb-6">
                    <button
                        className="w-10 h-10 flex items-center justify-center rounded-full bg-bg-tertiary text-text-secondary hover:bg-primary hover:text-white transition-all cursor-pointer"
                        onClick={() => router.push('/mesas')}
                    >
                        <ArrowLeft size={20} />
                    </button>
                    <h1 className="text-2xl font-bold">Mesa {String(mesa.numero_mesa).padStart(2, '0')}</h1>
                </div>
                <div className="bg-bg-secondary p-8 rounded-2xl border border-border text-center flex flex-col items-center shadow-lg">
                    <div className="size-16 rounded-full bg-blue-500/20 text-blue-500 flex items-center justify-center mb-4">
                        <Combine size={32} />
                    </div>
                    <h2 className="text-xl font-bold text-text-primary mb-2">Mesa Agrupada</h2>
                    <p className="text-text-secondary mb-8 max-w-sm">Esta mesa encontra-se agrupada. Os pedidos devem ser lançados na <strong>mesa principal {activeSession.garcom?.replace('[Unida c/ Mesa ', '').replace(']', '')}</strong>.</p>
                    <button 
                        onClick={async () => {
                            try {
                                await separarMesa(activeSession.id);
                                router.push('/mesas');
                            } catch (e) {
                                console.error('Erro ao separar mesa', e);
                            }
                        }}
                        className="bg-bg-tertiary text-text-primary px-6 py-3 rounded-xl font-bold hover:bg-bg-card transition-colors shadow-sm"
                    >
                        Separar / Liberar Mesa
                    </button>
                </div>
            </div>
        );
    }

    const allItems = activeSession?.items || [];
    const unconfirmedItems = allItems.filter((item: any) => !item.enviado_cozinha);
    const totalItems = allItems.length;
    const subtotal = activeSession?.valor_parcial || 0;
    const taxaServico = taxaServicoEnabled ? subtotal * (taxaServicoPercent / 100) : 0;
    const desconto = 0;
    const totalFinal = subtotal + taxaServico - desconto;
    const splitValue = splitCount > 0 ? totalFinal / splitCount : 0;

    const handleAbrirMesa = async () => {
        try {
            await abrirMesa(mesa.id, nomeGarcom.trim());
            alert("Mesa aberta com sucesso!");
            // No manual reload needed due to useLiveQuery
        } catch (error) {
            console.error("Erro ao abrir mesa:", error);
            alert("Erro ao abrir mesa.");
        }
    };

    const handleAddItem = async (produto: Product) => {
        if (!activeSession) return;
        setAddingItem(true);
        try {
            await addSessionItem(activeSession.id, {
                id: produto.id,
                nome: produto.name,
                preco: produto.price,
            });
            alert(`${produto.name} adicionado.`);
            // No manual reload needed due to useLiveQuery
        } catch (error) {
            console.error("Erro ao adicionar produto:", error);
            alert("Erro ao adicionar produto.");
        } finally {
            setAddingItem(false);
        }
    };

    const handleConfirmarPagamento = async () => {
        if (!activeSession || !selectedPayment) return;
        setClosingMesa(true);
        try {
            await fecharMesaSessao(
                activeSession.id,
                selectedPayment as 'credito' | 'debito' | 'pix' | 'dinheiro',
                taxaServico, // Passando o valor em R$ calculado acima
                desconto,
                totalFinal
            );
            alert("Pagamento confirmado e mesa fechada!");
            router.push('/mesas'); // Voltar pra listar mesas, pois a mesa agora está suja/livre
        } catch (error: unknown) {
            console.error("Erro ao fechar conta:", error);
            const errorMessage = error instanceof Error ? error.message : "Erro desconhecido";
            alert(`Erro ao fechar conta: ${errorMessage}`);
        } finally {
            setClosingMesa(false);
        }
    };

    const handleConfirmarItens = async () => {
        if (!activeSession || !user) return;
        setIsConfirming(true);
        try {
            await confirmarItensMesa(activeSession.id, mesa.numero_mesa, user.id, unconfirmedItems);
            alert("Itens enviados para a cozinha com sucesso!");
            // No manual reload needed due to useLiveQuery
        } catch (error) {
            console.error("Erro ao enviar para cozinha:", error);
            alert("Erro ao enviar para a cozinha.");
        } finally {
            setIsConfirming(false);
        }
    };

    const handleImprimirPrevia = async () => {
        if (!activeSession) return;

        const orderData = {
            id: activeSession.id,
            order_number: mesa.numero_mesa,
            customer_name: `Mesa ${mesa.numero_mesa}`,
            customer_phone: null,
            customer_address: null,
            status: 'pending',
            payment_method: 'money',
            payment_status: 'pending',
            subtotal: subtotal,
            delivery_fee: 0,
            total: subtotal,
            notes: null,
            is_delivery: false,
            created_at: activeSession.opened_at || new Date().toISOString(),
            items: allItems.map((item: any) => ({
                id: item.id,
                product_name: item.product_name || 'Produto',
                quantity: item.quantidade,
                unit_price: item.preco_unitario,
                total: item.preco_total,
                notes: item.observacao
            }))
        };

        await printOrder(orderData, { type: 'customer', appName: userSettings?.app_name || 'Cola Aí' });
    };

    const handleImprimirFechamento = async () => {
        if (!activeSession) return;

        const orderData = {
            id: activeSession.id,
            order_number: mesa.numero_mesa,
            customer_name: `Mesa ${mesa.numero_mesa}`,
            customer_phone: null,
            customer_address: null,
            status: 'closed',
            payment_method: selectedPayment || 'money',
            payment_status: 'paid',
            subtotal: subtotal,
            delivery_fee: 0,
            total: totalFinal,
            notes: null,
            is_delivery: false,
            created_at: activeSession.opened_at || new Date().toISOString(),
            items: allItems.map((item: any) => ({
                id: item.id,
                product_name: item.product_name || 'Produto',
                quantity: item.quantidade,
                unit_price: item.preco_unitario,
                total: item.preco_total,
                notes: item.observacao
            })),
            service_fee: taxaServicoEnabled ? taxaServico : 0,
            coupon_discount: desconto
        };

        // Wait, print.ts doesn't have a 'taxa_servico' field in OrderData. 
        // It has 'delivery_fee'. I might use delivery_fee as service fee for tables? 
        // Or I should patch print.ts to support service fee.

        // Let's check generateCustomerReceiptHTML in print.ts again.
        // It shows: ${order.delivery_fee > 0 ? `<span>Taxa de Entrega</span><span>${formatCurrency(order.delivery_fee)}</span>` : ''}

        // I'll pass taxaServico as delivery_fee for now or improve print.ts.
        // Given the requirement "100% funcionais com os dados necessarios", 
        // I should probably add service_fee to OrderData in print.ts.

        await printOrder({
            ...orderData,
            service_fee: taxaServico
        }, { type: 'customer', appName: userSettings?.app_name || 'Cola Aí' });
    };

    const getStatusStyle = () => {
        switch (status) {
            case 'livre': return { text: 'text-emerald-500', bg: 'bg-emerald-500/10', border: 'border-emerald-500/20', label: 'Livre' };
            case 'ocupada': return { text: 'text-red-500', bg: 'bg-red-500/10', border: 'border-red-500/20', label: 'Ocupada' };
            case 'fechando': return { text: 'text-amber-500', bg: 'bg-amber-500/10', border: 'border-amber-500/20', label: 'Pedindo Conta' };
            case 'suja': return { text: 'text-blue-500', bg: 'bg-blue-500/10', border: 'border-blue-500/20', label: 'Em Limpeza' };
            default: return { text: 'text-text-muted', bg: 'bg-bg-tertiary', border: 'border-border', label: status };
        }
    };

    const s = getStatusStyle();

    return (
        <div className="max-w-[1200px] mx-auto animate-fadeIn">
            {/* Header — same pattern as pedidos/[id] */}
            <div className="flex items-center gap-4 mb-6">
                <button
                    className="w-10 h-10 flex items-center justify-center rounded-full bg-bg-tertiary text-text-secondary hover:bg-primary hover:text-white transition-all cursor-pointer"
                    onClick={() => router.push('/mesas')}
                >
                    <ArrowLeft size={20} />
                </button>
                <div className="flex-1">
                    <div className="flex items-center gap-3">
                        <h1 className="text-2xl font-bold">Mesa {String(mesa.numero_mesa).padStart(2, '0')}</h1>
                        <span className={cn("px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider border", s.bg, s.text, s.border)}>
                            {s.label}
                        </span>
                        {groupedCount > 0 && (
                            <button 
                                onClick={async () => {
                                    if (confirm(`Deseja desagrupar as ${groupedCount} mesa(s) vinculada(s)?`)) {
                                        try {
                                            await desagruparTodas(mesa.numero_mesa);
                                            setGroupedCount(0);
                                            alert('Mesas desagrupadas!');
                                        } catch (_) {
                                            alert('Erro ao desagrupar mesas.');
                                        }
                                    }
                                }}
                                className="bg-blue-500/10 text-blue-500 text-xs px-3 py-1 rounded-full font-semibold border border-blue-500/20 hover:bg-blue-500/20 transition-colors flex items-center gap-1"
                            >
                                <Combine size={12} />
                                Desagrupar ({groupedCount})
                            </button>
                        )}
                    </div>
                    <p className="text-text-secondary flex items-center gap-1 mt-1">
                        <Clock size={14} />
                        {activeSession?.opened_at
                            ? `Aberta às ${new Date(activeSession.opened_at).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}`
                            : 'A mesa não está em atendimento'}
                    </p>
                </div>
                <div className="flex items-center gap-3">
                    {totalItems > 0 && (
                        <div className="text-right mr-2 hidden sm:block">
                            <p className="text-[10px] text-text-muted uppercase font-bold">Total Parcial</p>
                            <p className="text-xl font-black text-primary">{formatCurrency(subtotal)}</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Tab Navigation */}
            {status !== 'livre' && status !== 'suja' && (
                <div className="flex items-center gap-6 mb-6 border-b border-border pb-3">
                    <button
                        className={cn(
                            "text-sm font-medium transition-colors pb-1 cursor-pointer",
                            view === 'detalhes'
                                ? "text-primary font-bold border-b-2 border-primary"
                                : "text-text-secondary hover:text-primary"
                        )}
                        onClick={() => setView('detalhes')}
                    >
                        Resumo do Pedido
                    </button>
                    <button
                        className={cn(
                            "text-sm font-medium transition-colors pb-1 cursor-pointer",
                            view === 'pagamento'
                                ? "text-primary font-bold border-b-2 border-primary"
                                : "text-text-secondary hover:text-primary"
                        )}
                        onClick={() => setView('pagamento')}
                        disabled={totalItems === 0}
                    >
                        Pagamento da Conta
                    </button>
                </div>
            )}

            {status === 'livre' || status === 'suja' ? (
                /* ======== VIEW: ABRIR MESA / LIMPAR ======== */
                <div className="flex items-center justify-center h-64 mt-12">
                    <Card className="max-w-md w-full p-8! flex flex-col items-center">
                        <UtensilsCrossed className="w-16 h-16 text-text-muted mb-4" />
                        <h2 className="text-xl font-bold mb-2">
                            {status === 'livre' ? 'Mesa Livre' : 'Mesa em Limpeza'}
                        </h2>
                        <p className="text-text-secondary text-center text-sm mb-6">
                            {status === 'livre'
                                ? 'Esta mesa encontra-se livre no momento. Deseja iniciar um novo atendimento?'
                                : 'Esta mesa foi marcada como suja após o fechamento da última conta.'}
                        </p>

                        {status === 'livre' && (
                            <div className="w-full relative space-y-4">
                                <div>
                                    <label className="text-xs font-bold uppercase text-text-muted mb-1 flex">Nome do Garçom</label>
                                    <input
                                        type="text"
                                        placeholder="Ex: João Silva"
                                        value={nomeGarcom}
                                        onChange={(e) => setNomeGarcom(e.target.value)}
                                        className="w-full bg-bg-tertiary border border-border rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-primary text-text-primary outline-none"
                                    />
                                </div>
                                <button
                                    onClick={handleAbrirMesa}
                                    className="w-full bg-primary hover:bg-primary-dark text-white font-bold py-3 rounded-xl flex items-center justify-center gap-2 transition-transform active:scale-[0.98] shadow-lg shadow-primary/20 cursor-pointer"
                                >
                                    <PlusCircle className="w-5 h-5" /> Iniciar Atendimento
                                </button>
                            </div>
                        )}

                        {status === 'suja' && (
                            <button
                                onClick={async () => {
                                    // Apenas marcar como livre para fluxo de demonstração ou um service especifico
                                    alert("Mesa marcada como limpa/livre!");
                                    // Isso requereria um service func, mas como mockamos workflow:
                                    // router.back() ou recarregar...
                                    window.location.reload();
                                }}
                                className="w-full bg-emerald-500 hover:bg-emerald-600 text-white font-bold py-3 rounded-xl flex items-center justify-center gap-2 transition-transform active:scale-[0.98] shadow-lg shadow-emerald-500/20 cursor-pointer"
                            >
                                <CheckCircle className="w-5 h-5" /> Liberar Mesa
                            </button>
                        )}
                    </Card>
                </div>
            ) : view === 'detalhes' ? (
                <div className="flex flex-col lg:flex-row gap-6">
                    {/* Main Content */}
                    <div className="flex-[1.5] flex flex-col gap-6">
                        {/* Status Card */}
                        <Card className="p-4!">
                            <div className="flex justify-between items-center">
                                <div>
                                    <span className="text-sm text-text-muted">Status da Mesa</span>
                                    <span className={cn('block mt-1 px-3 py-1 rounded-full text-sm font-medium w-fit', s.bg, s.text)}>
                                        {s.label}
                                    </span>
                                </div>
                                <div className="text-right">
                                    <span className="text-sm text-text-muted">Garçom</span>
                                    <span className="block mt-1 text-lg font-semibold">{activeSession?.garcom || 'Nenhum'}</span>
                                </div>
                            </div>
                        </Card>

                        {/* Stats Row */}
                        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                            <Card className="p-4!">
                                <p className="text-text-muted text-[10px] font-bold uppercase tracking-widest">Total Consumido</p>
                                <p className="text-text-primary text-2xl font-bold mt-1">{formatCurrency(subtotal)}</p>
                            </Card>
                            <Card className="p-4!">
                                <p className="text-text-muted text-[10px] font-bold uppercase tracking-widest">Qtd. Pessoas</p>
                                <p className="text-text-primary text-2xl font-bold mt-1">{mesa.capacidade}</p>
                            </Card>
                            <Card className="p-4!">
                                <p className="text-text-muted text-[10px] font-bold uppercase tracking-widest">Itens no Pedido</p>
                                <p className="text-text-primary text-2xl font-bold mt-1">{totalItems}</p>
                            </Card>
                        </div>

                        {/* Actions */}
                        <div className="flex gap-3">
                            <button
                                onClick={handleImprimirPrevia}
                                className="flex items-center gap-2 px-5 h-12 bg-bg-card text-text-primary rounded-lg font-bold hover:border-primary border border-border transition-all cursor-pointer"
                            >
                                <Printer className="w-5 h-5" />
                                <span className="hidden sm:inline">Imprimir Prévia</span>
                            </button>

                            {unconfirmedItems.length > 0 && (
                                <button
                                    className="flex items-center gap-2 px-5 h-12 bg-yellow-500 text-white rounded-lg font-bold hover:bg-yellow-600 transition-all shadow-lg shadow-yellow-500/20 cursor-pointer"
                                    onClick={handleConfirmarItens}
                                    disabled={isConfirming}
                                >
                                    {isConfirming ? (
                                        <Loader2 className="w-5 h-5 animate-spin" />
                                    ) : (
                                        <CheckCircle className="w-5 h-5" />
                                    )}
                                    <span>Confirmar {unconfirmedItems.length} Itens</span>
                                </button>
                            )}

                            {totalItems > 0 && (
                                <button
                                    className="flex items-center gap-2 px-5 h-12 bg-primary text-white rounded-lg font-bold hover:bg-primary-dark transition-all shadow-lg shadow-primary/20 cursor-pointer"
                                    onClick={() => setView('pagamento')}
                                >
                                    <ReceiptText className="w-5 h-5" />
                                    <span>Fechar Mesa</span>
                                </button>
                            )}
                        </div>

                        {/* Orders Table */}
                        <Card padding="none">
                            <div className="p-4 border-b border-border flex justify-between items-center">
                                <h3 className="font-bold text-text-primary">Itens do Pedido</h3>
                                <button className="text-primary font-bold text-xs hover:underline flex items-center gap-1 uppercase tracking-wider cursor-pointer">
                                    <History className="w-4 h-4" /> Histórico completo
                                </button>
                            </div>
                            {totalItems > 0 ? (
                                <table className="w-full text-left border-collapse">
                                    <thead>
                                        <tr className="bg-bg-primary/50 border-b border-border">
                                            <th className="px-4 py-3 text-text-muted font-bold text-[10px] uppercase tracking-wider">Item</th>
                                            <th className="px-4 py-3 text-text-muted font-bold text-[10px] uppercase tracking-wider">Qtd</th>
                                            <th className="px-4 py-3 text-text-muted font-bold text-[10px] uppercase tracking-wider hidden sm:table-cell">Valor Unit.</th>
                                            <th className="px-4 py-3 text-text-muted font-bold text-[10px] uppercase tracking-wider">Status</th>
                                            <th className="px-4 py-3 text-text-muted font-bold text-[10px] uppercase tracking-wider">Total</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-border">
                                        {allItems.map((item: any) => (
                                            <tr key={item.id} className="hover:bg-bg-card-hover transition-colors">
                                                <td className="px-4 py-3">
                                                    <div className="flex flex-col">
                                                        <span className="text-text-primary font-bold">{item.product_name}</span>
                                                        {item.observacao && <span className="text-text-muted text-xs">{item.observacao}</span>}
                                                    </div>
                                                </td>
                                                <td className="px-4 py-3 text-text-primary font-medium">{String(item.quantidade).padStart(2, '0')}</td>
                                                <td className="px-4 py-3 text-text-primary hidden sm:table-cell">{formatCurrency(item.preco_total / item.quantidade)}</td>
                                                <td className="px-4 py-3">
                                                    {item.enviado_cozinha ? (
                                                        (() => {
                                                            const kitchenStatus = item.orders?.status || 'pending';
                                                            switch (kitchenStatus) {
                                                                case 'preparing':
                                                                    return (
                                                                        <span className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-bold bg-amber-500/10 text-amber-500 border border-amber-500/20">
                                                                            <span className="size-1.5 rounded-full bg-amber-500 animate-pulse" /> Em Preparo
                                                                        </span>
                                                                    );
                                                                case 'ready':
                                                                    return (
                                                                        <span className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-bold bg-emerald-500/10 text-emerald-500 border border-emerald-500/20 shadow-[0_0_8px_rgba(16,185,129,0.2)]">
                                                                            <span className="size-1.5 rounded-full bg-emerald-500" /> Pronto ✅
                                                                        </span>
                                                                    );
                                                                case 'delivered':
                                                                case 'delivering':
                                                                    return (
                                                                        <span className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-bold bg-blue-500/10 text-blue-500 border border-blue-500/20">
                                                                            <span className="size-1.5 rounded-full bg-blue-500" /> Entregue
                                                                        </span>
                                                                    );
                                                                default:
                                                                    return (
                                                                        <span className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-bold bg-primary/10 text-primary border border-primary/20">
                                                                            <span className="size-1.5 rounded-full bg-primary" /> Na Fila
                                                                        </span>
                                                                    );
                                                            }
                                                        })()
                                                    ) : (
                                                        <span className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-bold bg-yellow-500/10 text-yellow-500 border border-yellow-500/20">
                                                            <span className="size-1.5 rounded-full bg-yellow-500" /> A Confirmar
                                                        </span>
                                                    )}
                                                </td>
                                                <td className="px-4 py-3 text-text-primary font-bold">{formatCurrency(item.preco_total)}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            ) : (
                                <div className="py-12 text-center text-text-muted">
                                    Nenhum item adicionado ainda.
                                </div>
                            )}
                        </Card>
                    </div>

                    {/* Right Sidebar: Quick Add */}
                    <aside className="w-full lg:w-96 shrink-0">
                        <Card padding="none" className="overflow-hidden">
                            <div className="p-4 border-b border-border flex items-center justify-between">
                                <h3 className="text-text-primary font-bold">Adicionar Pedido</h3>
                                <PlusCircle className="text-text-muted w-5 h-5" />
                            </div>
                            <div className="p-4 space-y-4">
                                {/* Search Box */}
                                <div className="relative group">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <Search className="h-4 text-text-muted group-focus-within:text-primary transition-colors" />
                                    </div>
                                    <input
                                        type="text"
                                        placeholder="Buscar produto..."
                                        value={searchTerm}
                                        onChange={(e) => setSearchTerm(e.target.value)}
                                        className="w-full bg-bg-tertiary border border-border rounded-xl pl-10 pr-4 py-2 text-sm text-text-primary placeholder:text-text-muted focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all"
                                    />
                                    {searchTerm && (
                                        <button
                                            onClick={() => setSearchTerm('')}
                                            className="absolute inset-y-0 right-0 pr-3 flex items-center text-text-muted hover:text-text-primary cursor-pointer"
                                        >
                                            <span className="text-lg">×</span>
                                        </button>
                                    )}
                                </div>

                                {/* Category Tabs */}
                                <div className="flex gap-2 overflow-x-auto pb-3 scrollbar-hide">
                                    {categories.map((cat: any) => (
                                        <button
                                            key={cat.id}
                                            onClick={() => setActiveCategory(cat.id)}
                                            className={cn(
                                                "px-4 py-1.5 rounded-full border text-xs font-semibold whitespace-nowrap transition-colors cursor-pointer",
                                                activeCategory === cat.id
                                                    ? "bg-primary border-primary text-white"
                                                    : "bg-bg-tertiary border-border text-text-secondary hover:border-primary/30"
                                            )}
                                        >
                                            {cat.name}
                                        </button>
                                    ))}
                                </div>
                                {/* Product List */}
                                <div className="grid grid-cols-1 gap-4 mt-2">
                                    {filteredProducts.map(prod => (
                                        <div key={prod.id} className="group relative flex flex-col rounded-xl overflow-hidden bg-bg-tertiary border border-border cursor-pointer hover:border-primary/50 hover:shadow-lg hover:shadow-primary/5 transition-all">
                                            <div className="h-28 w-full bg-cover bg-center" style={{ backgroundImage: `url('${prod.image_url || '/image-placeholder.jpeg'}')` }} />
                                            <div className="p-3">
                                                <p className="text-text-primary font-bold text-sm line-clamp-1">{prod.name}</p>
                                                <p className="text-primary font-bold text-base mt-0.5">{formatCurrency(prod.price)}</p>
                                                <button
                                                    onClick={() => handleAddItem(prod)}
                                                    disabled={addingItem}
                                                    className="mt-3 w-full py-2 bg-bg-card text-text-primary rounded-lg text-[10px] font-bold flex items-center justify-center gap-1 group-hover:bg-primary group-hover:text-white transition-colors uppercase tracking-wider cursor-pointer disabled:opacity-50"
                                                >
                                                    {addingItem ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <PlusCircle className="w-3.5 h-3.5" />} ADICIONAR
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </Card>
                    </aside>
                </div>
            ) : (
                /* ======== VIEW: PAGAMENTO ======== */
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
                    {/* Left Column: Summary & Splitting */}
                    <div className="lg:col-span-7 flex flex-col gap-6">
                        {/* Order Summary */}
                        <Card padding="none">
                            <div className="p-4 border-b border-border flex justify-between items-center">
                                <h3 className="font-bold flex items-center gap-2 text-text-primary">
                                    <ReceiptText className="text-primary w-5 h-5" /> Itens Consumidos
                                </h3>
                                <span className="text-xs bg-bg-tertiary px-2 py-1 rounded font-medium text-text-secondary">{totalItems} {totalItems === 1 ? 'Item' : 'Itens'}</span>
                            </div>
                            <div className="divide-y divide-border/50 max-h-80 overflow-y-auto custom-scrollbar">
                                {allItems.map(item => (
                                    <div key={item.id} className="flex items-center justify-between p-4 hover:bg-bg-card-hover transition-colors">
                                        <div className="flex flex-col">
                                            <p className="font-semibold text-text-primary">{item.product_name}</p>
                                            <p className="text-xs text-text-muted">{item.quantidade}x {formatCurrency(item.preco_total / item.quantidade)}</p>
                                        </div>
                                        <p className="font-bold text-text-primary">{formatCurrency(item.preco_total)}</p>
                                    </div>
                                ))}
                            </div>
                        </Card>

                        {/* Split Bill */}
                        <Card>
                            <h3 className="font-bold mb-4 flex items-center gap-2 text-text-primary">
                                <Users className="text-primary w-5 h-5" /> Dividir Conta
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div className="p-4 rounded-xl border border-primary/20 bg-primary/5">
                                    <p className="text-xs font-bold uppercase text-text-muted mb-2">Por Pessoa</p>
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-3">
                                            <button onClick={() => setSplitCount(Math.max(1, splitCount - 1))} className="size-8 rounded-full bg-primary/20 flex items-center justify-center text-primary font-bold hover:bg-primary hover:text-white transition-colors cursor-pointer"><Minus className="w-4 h-4" /></button>
                                            <span className="text-lg font-bold w-6 text-center">{String(splitCount).padStart(2, '0')}</span>
                                            <button onClick={() => setSplitCount(splitCount + 1)} className="size-8 rounded-full bg-primary flex items-center justify-center text-white font-bold hover:bg-primary-dark transition-colors cursor-pointer"><Plus className="w-4 h-4" /></button>
                                        </div>
                                        <div className="text-right">
                                            <p className="text-xs text-text-muted leading-none mb-1">Cada um paga</p>
                                            <p className="text-lg font-black text-primary">{formatCurrency(splitValue)}</p>
                                        </div>
                                    </div>
                                </div>
                                <div className="p-4 rounded-xl border border-border flex flex-col justify-center">
                                    <p className="text-xs font-bold uppercase text-text-muted mb-2">Valor Personalizado</p>
                                    <div className="relative">
                                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-text-muted font-bold">R$</span>
                                        <input type="number" placeholder="0,00" className="w-full bg-transparent border border-border rounded-lg pl-10 py-2 focus:ring-primary focus:border-primary text-text-primary" />
                                    </div>
                                </div>
                            </div>
                        </Card>
                    </div>

                    {/* Right Column: Totals & Payments */}
                    <div className="lg:col-span-5 flex flex-col gap-6">
                        {/* Payment Methods */}
                        <Card>
                            <h3 className="font-bold mb-4 flex items-center gap-2 text-text-primary">
                                <CreditCard className="text-primary w-5 h-5" /> Método de Pagamento
                            </h3>
                            <div className="grid grid-cols-2 gap-3">
                                <button
                                    onClick={() => setSelectedPayment('credito')}
                                    className={cn("flex flex-col items-center justify-center p-4 rounded-xl border-2 gap-2 transition-all cursor-pointer", selectedPayment === 'credito' ? "border-primary bg-primary/10 text-primary" : "border-transparent bg-bg-tertiary hover:border-primary/50 text-text-muted")}
                                >
                                    <CreditCard className="w-6 h-6" />
                                    <span className="text-xs font-bold">Crédito</span>
                                </button>
                                <button
                                    onClick={() => setSelectedPayment('debito')}
                                    className={cn("flex flex-col items-center justify-center p-4 rounded-xl border-2 gap-2 transition-all cursor-pointer", selectedPayment === 'debito' ? "border-primary bg-primary/10 text-primary" : "border-transparent bg-bg-tertiary hover:border-primary/50 text-text-muted")}
                                >
                                    <CreditCard className="w-6 h-6" />
                                    <span className="text-xs font-bold">Débito</span>
                                </button>
                                <button
                                    onClick={() => setSelectedPayment('pix')}
                                    className={cn("flex flex-col items-center justify-center p-4 rounded-xl border-2 gap-2 transition-all cursor-pointer", selectedPayment === 'pix' ? "border-primary bg-primary/10 text-primary" : "border-transparent bg-bg-tertiary hover:border-primary/50 text-text-muted")}
                                >
                                    <QrCode className="w-6 h-6" />
                                    <span className="text-xs font-bold">PIX</span>
                                </button>
                                <button
                                    onClick={() => setSelectedPayment('dinheiro')}
                                    className={cn("flex flex-col items-center justify-center p-4 rounded-xl border-2 gap-2 transition-all cursor-pointer", selectedPayment === 'dinheiro' ? "border-primary bg-primary/10 text-primary" : "border-transparent bg-bg-tertiary hover:border-primary/50 text-text-muted")}
                                >
                                    <Banknote className="w-6 h-6" />
                                    <span className="text-xs font-bold">Dinheiro</span>
                                </button>
                            </div>
                            
                            {selectedPayment === 'dinheiro' && (
                                <div className="mt-4 p-4 border border-border rounded-xl bg-bg-tertiary animate-fadeIn">
                                    <label className="text-xs font-bold uppercase text-text-muted mb-2 block">
                                        Valor Recebido do Cliente (R$)
                                    </label>
                                    <div className="relative">
                                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-text-muted font-bold">R$</span>
                                        <input
                                            type="number"
                                            value={valorRecebido}
                                            onChange={(e) => setValorRecebido(e.target.value ? Number(e.target.value) : '')}
                                            placeholder="Ex: 50.00"
                                            step="0.01"
                                            className="w-full bg-bg-primary border border-border rounded-lg pl-10 pr-4 py-2 focus:ring-primary focus:border-primary text-text-primary outline-none"
                                        />
                                    </div>
                                </div>
                            )}
                        </Card>

                        {/* Ticket / Discount */}
                        <Card className="flex items-center gap-3 p-4!">
                            <Ticket className="text-text-muted w-5 h-5 shrink-0" />
                            <input type="text" placeholder="Código de desconto..." className="flex-1 bg-transparent border-none focus:ring-0 text-sm p-0 text-text-primary placeholder:text-text-muted outline-none" />
                            <button className="text-primary text-xs font-bold uppercase tracking-tight hover:underline cursor-pointer">Aplicar</button>
                        </Card>

                        {/* Summary & Confirm */}
                        <Card>
                            <div className="space-y-3 mb-5">
                                <div className="flex justify-between text-text-muted text-sm">
                                    <span>Subtotal</span>
                                    <span className="font-medium">{formatCurrency(subtotal)}</span>
                                </div>

                                {taxaServicoEnabled && (
                                    <div className="flex justify-between text-text-muted text-sm">
                                        <div className="flex items-center gap-2">
                                            <span>Taxa de Serviço ({taxaServicoPercent}%)</span>
                                            <Info className="w-3.5 h-3.5" />
                                        </div>
                                        <span className="font-medium">{formatCurrency(taxaServico)}</span>
                                    </div>
                                )}

                                {desconto > 0 && (
                                    <div className="flex justify-between text-emerald-500 text-sm font-medium">
                                        <span>Descontos</span>
                                        <span>- {formatCurrency(desconto)}</span>
                                    </div>
                                )}
                                <div className="h-px bg-border my-2" />
                                <div className="flex justify-between items-end">
                                    <span className="text-lg font-medium text-text-primary">Total Final</span>
                                    <span className="text-3xl font-black text-primary">{formatCurrency(totalFinal)}</span>
                                </div>
                                {selectedPayment === 'dinheiro' && typeof valorRecebido === 'number' && valorRecebido >= totalFinal && (
                                    <div className="flex justify-between items-end mt-2 pt-3 border-t border-border/50 animate-fadeIn">
                                        <span className="text-lg font-bold text-text-secondary">Troco</span>
                                        <span className="text-2xl font-black text-emerald-500">{formatCurrency(valorRecebido - totalFinal)}</span>
                                    </div>
                                )}
                            </div>

                            <div className="flex flex-col gap-3">
                                <button
                                    onClick={handleConfirmarPagamento}
                                    disabled={!selectedPayment || closingMesa}
                                    className="w-full bg-primary hover:bg-primary-dark text-white font-bold py-4 rounded-xl flex items-center justify-center gap-3 transition-transform active:scale-[0.98] shadow-lg shadow-primary/20 cursor-pointer disabled:opacity-50 disabled:pointer-events-none"
                                >
                                    {closingMesa ? <Loader2 className="w-5 h-5 animate-spin" /> : <CheckCircle className="w-5 h-5" />}
                                    Confirmar Pagamento
                                </button>
                                <div className="grid grid-cols-2 gap-3">
                                    <button
                                        onClick={handleImprimirFechamento}
                                        className="bg-bg-tertiary hover:bg-bg-card-hover text-text-primary font-semibold py-3 rounded-xl flex items-center justify-center gap-2 transition-colors cursor-pointer border border-border"
                                    >
                                        <Printer className="w-4 h-4" /> Imprimir
                                    </button>
                                    <button className="bg-bg-tertiary hover:bg-bg-card-hover text-text-primary font-semibold py-3 rounded-xl flex items-center justify-center gap-2 transition-colors cursor-pointer border border-border">
                                        <Share className="w-4 h-4" /> Enviar NF-e
                                    </button>
                                </div>
                            </div>
                        </Card>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useRouter, useParams } from 'next/navigation';
import { FiArrowLeft, FiClock, FiUser, FiPhone, FiMapPin, FiCreditCard, FiPrinter, FiCheck, FiChevronDown } from 'react-icons/fi';
import { GiCookingPot } from 'react-icons/gi';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import PixQRCode from '@/components/pix/PixQRCode';
import { useToast } from '@/components/ui/Toast';
import { useAuth } from '@/contexts/AuthContext';
import { useSingleOrderCache } from '@/hooks/useDataCache';
import { confirmOrderPayment } from '@/lib/dataAccess';
import { printOrder, printCustomerReceipt, printKitchenTicket } from '@/lib/print';
import { formatCurrency } from '@/hooks/useFormatters';
import { cn } from '@/lib/utils';

export default function OrderDetailsPage() {
    const { user, userSettings } = useAuth();
    const router = useRouter();
    const params = useParams();
    const orderId = params.id as string;
    
    const { order: cachedOrder, loading, error: cacheError } = useSingleOrderCache(orderId);
    
    const [showPrintMenu, setShowPrintMenu] = useState(false);
    const [printing, setPrinting] = useState(false);
    const appName = userSettings?.app_name || 'Cola Aí';
    const toast = useToast();

    // Map cachedOrder to local interface if needed, or use directly
    const order = cachedOrder ? {
        ...cachedOrder,
        items: (cachedOrder.order_items || []).map(item => ({
            ...item,
            total: item.total || (item.quantity * item.unit_price)
        }))
    } : null;

    const formatDateFull = (date: string) => {
        try {
            return new Intl.DateTimeFormat('pt-BR', { 
                day: '2-digit', month: '2-digit', year: 'numeric', 
                hour: '2-digit', minute: '2-digit', 
                timeZone: 'America/Sao_Paulo' 
            }).format(new Date(date));
        } catch (e) {
            return 'Data inválida';
        }
    };

    const updatePaymentStatus = async () => {
        if (!order || !user) return;
        try {
            await confirmOrderPayment(order as any, user.id);
            toast.success('Pagamento confirmado!');
        } catch (e) { 
            console.error(e); 
            toast.error('Erro ao atualizar status do pagamento'); 
        }
    };

    const getStatusLabel = (status: string) => ({ pending: 'Aguardando', preparing: 'Preparando', ready: 'Pronto', delivering: 'Entregando', delivered: 'Entregue', cancelled: 'Cancelado' }[status] || status);
    const getPaymentLabel = (method: string) => ({ money: 'Dinheiro', credit: 'Crédito', debit: 'Débito', pix: 'PIX' }[method] || method);

    const handlePrintBoth = async () => { if (!order) return; setPrinting(true); setShowPrintMenu(false); try { await printOrder(order as any, { type: 'both', appName }); } finally { setPrinting(false); } };
    const handlePrintCustomer = async () => { if (!order) return; setPrinting(true); setShowPrintMenu(false); try { await printCustomerReceipt(order as any, appName); } finally { setPrinting(false); } };
    const handlePrintKitchen = async () => { if (!order) return; setPrinting(true); setShowPrintMenu(false); try { await printKitchenTicket(order as any); } finally { setPrinting(false); } };
    
    if (loading && !order) return <div className="max-w-[1400px] mx-auto"><div className="h-[200px] bg-bg-tertiary rounded-xl animate-pulse mb-4" /><div className="h-[300px] bg-bg-tertiary rounded-xl animate-pulse" /></div>;
    if (cacheError) return <div className="max-w-[800px] mx-auto p-8 text-center"><p className="text-error mb-4">Erro ao carregar pedido.</p><Button onClick={() => router.push('/pedidos')}>Voltar para Pedidos</Button></div>;
    if (!order) return <div className="max-w-[800px] mx-auto p-8 text-center"><p className="text-text-secondary mb-4">Pedido não encontrado.</p><Button onClick={() => router.push('/pedidos')}>Voltar para Pedidos</Button></div>;

    
    return (
        <div className="max-w-[1400px] mx-auto">
            {/* Header */}
                <div className="flex items-center gap-4 mb-6">
                    <button className="w-10 h-10 flex items-center justify-center rounded-full bg-bg-tertiary text-text-secondary hover:bg-primary hover:text-white transition-all" onClick={() => router.back()}><FiArrowLeft size={20} /></button>
                    <div className="flex-1"><h1 className="text-2xl font-bold">Pedido #{order.order_number}</h1><p className="text-text-secondary flex items-center gap-1"><FiClock size={14} /> {formatDateFull(order.created_at || new Date().toISOString())}</p></div>
                    <div className="relative">
                        <Button variant="secondary" leftIcon={<FiPrinter />} rightIcon={<FiChevronDown />} onClick={() => setShowPrintMenu(!showPrintMenu)} disabled={printing}>{printing ? 'Imprimindo...' : 'Imprimir'}</Button>
                        {showPrintMenu && (
                            <div className="absolute right-0 top-full mt-2 w-[220px] bg-bg-card border border-border rounded-lg shadow-lg z-10 overflow-hidden">
                                <button onClick={handlePrintBoth} className="w-full flex items-center gap-3 px-4 py-3 text-left hover:bg-bg-tertiary transition-all"><FiPrinter className="text-primary" /><div><span className="block font-medium">Imprimir Tudo</span><small className="text-text-muted text-xs">Cliente + Cozinha</small></div></button>
                                <button onClick={handlePrintCustomer} className="w-full flex items-center gap-3 px-4 py-3 text-left hover:bg-bg-tertiary transition-all border-t border-border"><FiUser className="text-primary" /><div><span className="block font-medium">Via do Cliente</span><small className="text-text-muted text-xs">Comprovante</small></div></button>
                                <button onClick={handlePrintKitchen} className="w-full flex items-center gap-3 px-4 py-3 text-left hover:bg-bg-tertiary transition-all border-t border-border"><GiCookingPot className="text-primary" /><div><span className="block font-medium">Comanda Cozinha</span><small className="text-text-muted text-xs">Para preparo</small></div></button>
                            </div>
                        )}
                    </div>
                </div>

                {/* Status Card */}
                <Card className="mb-4 p-4!">
                    <div className="flex justify-between items-center">
                        <div><span className="text-sm text-text-muted">Status do Pedido</span><span className={cn('block mt-1 px-3 py-1 rounded-full text-sm font-medium w-fit', order.status === 'pending' && 'bg-warning/20 text-warning', order.status === 'preparing' && 'bg-accent/20 text-accent', order.status === 'ready' && 'bg-primary/20 text-primary', order.status === 'delivered' && 'bg-success/20 text-success', order.status === 'cancelled' && 'bg-error/20 text-error')}>{getStatusLabel(order.status || 'pending')}</span></div>
                        <div className="text-right"><span className="text-sm text-text-muted">Tipo</span><span className="block mt-1 text-lg">{order.is_delivery ? '🚚 Entrega' : '🏪 Balcão'}</span></div>
                    </div>
                </Card>

                {/* Customer & Payment Info */}
                <Card className="mb-4">
                    <div className="flex items-center gap-2 text-text-primary font-medium mb-4"><FiUser /> Informações do Cliente</div>
                    <div className="grid grid-cols-2 gap-4 max-sm:grid-cols-1">
                        <div><span className="text-sm text-text-muted">Nome</span><span className="block mt-1">{order.customer_name}</span></div>
                        {order.customer_phone && <div><span className="text-sm text-text-muted">Telefone</span><span className="block mt-1">{order.customer_phone}</span></div>}
                        {order.is_delivery && order.customer_address && <div className="col-span-2"><span className="text-sm text-text-muted">Endereço</span><span className="block mt-1">{order.customer_address}</span></div>}
                    </div>
                    <div className="border-t border-border my-4" />
                    <div className="flex items-center gap-2 text-text-primary font-medium mb-4"><FiCreditCard /> Pagamento</div>
                    <div className="grid grid-cols-2 gap-4 max-sm:grid-cols-1">
                        <div><span className="text-sm text-text-muted">Método</span><span className="block mt-1">{getPaymentLabel(order.payment_method)}</span></div>
                        <div><span className="text-sm text-text-muted">Status</span><div className="flex items-center gap-3 mt-1"><span className={order.payment_status === 'paid' ? 'text-success' : 'text-warning'}>{order.payment_status === 'paid' ? 'Pago' : 'Pendente'}</span>{order.payment_status === 'pending' && <Button variant="primary" size="sm" leftIcon={<FiCheck />} onClick={updatePaymentStatus}>Pagamento Recebido</Button>}</div></div>
                    </div>
                    {order.payment_method === 'pix' && order.payment_status === 'pending' && userSettings?.pix_key && (<><div className="border-t border-border my-4" /><div className="flex justify-center"><PixQRCode pixKey={userSettings.pix_key} pixKeyType={userSettings.pix_key_type || 'cpf'} merchantName={appName} merchantCity={userSettings.merchant_city || 'Brasil'} amount={order.total} orderId={order.order_number} onPaymentConfirmed={updatePaymentStatus} /></div></>)}
                </Card>

                {/* Order Items */}
                <Card>
                    <div className="text-text-primary font-medium mb-4">Itens do Pedido</div>
                    <div className="flex flex-col">
                        {order.items.map((item) => (
                            <div key={item.id} className="flex justify-between items-start py-3 border-b border-border last:border-b-0">
                                <div><span className="font-medium">{item.quantity}x {item.product_name}</span>{item.notes && <span className="block text-sm text-text-muted mt-1">Obs: {item.notes}</span>}</div>
                                <span className="font-medium text-primary">{formatCurrency(item.total)}</span>
                            </div>
                        ))}
                    </div>
                    <div className="border-t border-border my-4" />
                    <div className="flex flex-col gap-2">
                        <div className="flex justify-between text-text-secondary"><span>Subtotal</span><span>{formatCurrency(order.subtotal)}</span></div>
                        {order.delivery_fee !== null && order.delivery_fee > 0 && <div className="flex justify-between text-text-secondary"><span>Taxa de Entrega</span><span>{formatCurrency(order.delivery_fee)}</span></div>}
                        {order.coupon_discount && order.coupon_discount > 0 && <div className="flex justify-between text-success"><span>Desconto</span><span>-{formatCurrency(order.coupon_discount)}</span></div>}
                        <div className="flex justify-between text-lg font-bold pt-2 border-t border-border"><span>Total</span><span className="text-primary">{formatCurrency(order.total)}</span></div>
                    </div>
                </Card>
            </div>
    );
}

'use client';

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import Link from 'next/link';
import {
    FiPlus,
    FiSearch,
    FiClock,
    FiMoreVertical,
    FiEye,
    FiEdit,
    FiTrash2
} from 'react-icons/fi';
import { FaWhatsapp } from 'react-icons/fa';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import Input from '@/components/ui/Input';
import { StatusBadge, PaymentMethodBadge, type OrderStatus, type PaymentMethod } from '@/components/ui/StatusBadge';
import { useToast } from '@/components/ui/Toast';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/lib/supabase';
import { formatCurrency, formatDateTime } from '@/hooks/useFormatters';
import { openWhatsAppNotification, shouldNotifyOnStatusChange, OrderDetails } from '@/lib/whatsapp';
import { logOrderStatusChange, logPaymentReceived } from '@/lib/actionLogger';
import { cn } from '@/lib/utils';
import { useOrdersCache } from '@/hooks/useDataCache';
import { updateLoyaltyPoints } from '@/app/actions/loyalty';
import { getStatusLabel } from '@/components/ui/StatusBadge';

// Função para disparar notificação local de status
async function sendStatusChangePush(userId: string, orderNumber: number, status: string) {
    try {
        await fetch('/api/push/send', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                userId,
                title: `Mudança no Pedido #${orderNumber}`,
                message: `O status do pedido mudou para: ${status}`,
                url: '/pedidos'
            })
        });
    } catch (e) {
        console.error('Push error:', e);
    }
}

interface Order {
    id: string;
    order_number: number;
    customer_name: string;
    customer_phone: string | null;
    customer_address: string | null;
    status: string | null;
    payment_method: string;
    payment_status: string | null;
    total: number;
    is_delivery: boolean | null;
    created_at: string | null;
    rating_token: string | null;
}

const statusOptions = [
    { value: 'all', label: 'Todos' },
    { value: 'pending', label: 'Aguardando' },
    { value: 'preparing', label: 'Preparando' },
    { value: 'ready', label: 'Pronto' },
    { value: 'delivering', label: 'Entregando' },
    { value: 'delivered', label: 'Entregue' },
    { value: 'cancelled', label: 'Cancelado' }
];

const ORDERS_PER_PAGE = 30;

export default function PedidosPage() {
    const { user, userSettings } = useAuth();
    const { orders: allOrders, loading, error: cacheError } = useOrdersCache();
    const [searchTerm, setSearchTerm] = useState('');
    const [statusFilter, setStatusFilter] = useState('all');
    const [showDropdown, setShowDropdown] = useState<string | null>(null);
    const [showWhatsAppModal, setShowWhatsAppModal] = useState<Order | null>(null);
    const [pendingStatusForModal, setPendingStatusForModal] = useState<string | null>(null);
    const [visibleCount, setVisibleCount] = useState(ORDERS_PER_PAGE);

    const toast = useToast();

    // ── Pre-processamento local ──
    const { filteredOrders, hasMore } = useMemo(() => {
        const filtered = allOrders.filter(order => {
            const matchesSearch = order.customer_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                                 order.order_number.toString().includes(searchTerm);
            const matchesStatus = statusFilter === 'all' || order.status === statusFilter;
            return matchesSearch && matchesStatus;
        });

        return {
            filteredOrders: filtered.slice(0, visibleCount),
            hasMore: filtered.length > visibleCount
        };
    }, [allOrders, searchTerm, statusFilter, visibleCount]);

    const ordersMap = useMemo(() => {
        const map = new Map<string, Order>();
        allOrders.forEach(o => map.set(o.id, o as Order));
        return map;
    }, [allOrders]);

    // ── Realtime: apenas para novos pedidos recebidos na nuvem ──
    useEffect(() => {
        if (!user) return;

        const subscription = supabase
            .channel('orders-realtime-page')
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'orders',
                    filter: `user_id=eq.${user.id}`
                },
                async () => {
                    const audio = new Audio('/notification.mp3');
                    audio.play().catch(() => { });
                    toast.info('Novo pedido recebido na nuvem!');
                    // Trigger a background sync to fetch the new order into Dexie
                    const { fetchOrders } = await import('@/lib/dataAccess');
                    await fetchOrders(user.id);
                }
            )
            .subscribe();

        return () => {
            subscription.unsubscribe();
        };
    }, [user, toast]);

    const loadMore = useCallback(() => {
        setVisibleCount(prev => prev + ORDERS_PER_PAGE);
    }, []);

    const sendWhatsAppNotification = (order: Order, newStatus: string) => {
        if (!order.customer_phone || !userSettings?.whatsapp_number) return;

        const orderDetails: OrderDetails = {
            order_number: order.order_number,
            customer_name: order.customer_name,
            customer_phone: order.customer_phone,
            total: order.total,
            status: newStatus,
            is_delivery: order.is_delivery ?? false,
            customer_address: order.customer_address || undefined,
            rating_token: order.rating_token || undefined
        };

        const notificationSettings = {
            whatsapp_number: userSettings.whatsapp_number,
            app_name: userSettings.app_name || 'Cola Aí'
        };

        const baseUrl = typeof window !== 'undefined' ? window.location.origin : '';
        openWhatsAppNotification(orderDetails, notificationSettings, newStatus, baseUrl);
    };

    // ── Wrapper de updateOrderStatus Local-First ──
    const updateOrderStatus = async (orderId: string, newStatus: string, sendNotification: boolean = false) => {
        const order = ordersMap.get(orderId);
        if (!order) return;

        try {
            const { updateOrder } = await import('@/lib/dataAccess');
            
            logOrderStatusChange(orderId, order.order_number, order.status || 'pending', newStatus);
            
            // Dexie update + Reactive UI refresh (instant)
            await updateOrder(orderId, { 
                status: newStatus, 
                updated_at: new Date().toISOString() 
            });

            toast.success(`Status atualizado para ${getStatusLabel(newStatus || 'pending')}`);

            if (sendNotification && order.customer_phone && shouldNotifyOnStatusChange(order.status || 'pending', newStatus)) {
                sendWhatsAppNotification(order, newStatus);
            }
            if (user) {
                sendStatusChangePush(user.id, order.order_number, newStatus);
            }
        } catch (err) {
            console.error('Error updating status:', err);
            toast.error('Erro ao atualizar status');
        }

        setShowDropdown(null);
        setShowWhatsAppModal(null);
    };

    const handleStatusChangeWithNotification = (order: Order, newStatus: string) => {
        if (order.customer_phone && shouldNotifyOnStatusChange(order.status || 'pending', newStatus)) {
            setShowWhatsAppModal(order);
            setPendingStatusForModal(newStatus);
        } else {
            updateOrderStatus(order.id, newStatus, false);
        }
    };

    // ── Confirmar pagamento Local-First ──
    const updatePaymentStatus = async (orderId: string) => {
        const order = ordersMap.get(orderId);
        if (!order) return;

        try {
            const { updateOrder } = await import('@/lib/dataAccess');
            
            logPaymentReceived(orderId, order.order_number, order.total, order.payment_method);

            await updateOrder(orderId, { 
                payment_status: 'paid', 
                updated_at: new Date().toISOString() 
            });
            
            toast.success('Pagamento confirmado!');

            if (order.customer_phone && user) {
                void updateLoyaltyPoints({
                    userId: user.id,
                    orderId: order.id,
                    orderNumber: order.order_number,
                    orderTotal: order.total,
                    customerPhone: order.customer_phone,
                });
            }
        } catch (err) {
            console.error('Error updating payment:', err);
            toast.error('Erro ao confirmar pagamento');
        }
    };

    // ── Excluir pedido Local-First ──
    const deleteOrder = async (orderId: string) => {
        if (!confirm('Tem certeza que deseja excluir este pedido?')) return;
        
        try {
            const { deleteOrder } = await import('@/lib/dataAccess');
            await deleteOrder(orderId);
            toast.success('Pedido excluído');
        } catch (err) {
            console.error('Error deleting order:', err);
            toast.error('Erro ao excluir pedido');
        }
    };


    return (
        <div className="max-w-[1400px] mx-auto">
            {/* Header */}
            <div className="flex items-start justify-between mb-8 gap-5 max-md:flex-col">
                <div>
                    <h1 className="text-[2rem] font-bold mb-2">Pedidos</h1>
                    <p className="text-text-secondary">Gerencie todos os seus pedidos</p>
                </div>
                <Link href="/pedidos/novo">
                    <Button leftIcon={<FiPlus />}>Novo Pedido</Button>
                </Link>
            </div>

            {/* Filters */}
            <Card className="mb-6 px-5! py-4!">
                <div className="flex flex-col gap-4">
                    <div className="max-w-[400px]">
                        <Input
                            placeholder="Buscar por cliente ou número..."
                            leftIcon={<FiSearch />}
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>

                    <div className="flex flex-wrap gap-2">
                        {statusOptions.map((option) => (
                            <button
                                key={option.value}
                                className={cn(
                                    'px-4 py-2 bg-bg-tertiary border border-border rounded-full text-text-secondary text-sm cursor-pointer transition-all duration-fast hover:border-border-light hover:text-text-primary',
                                    statusFilter === option.value && 'bg-primary border-primary text-white'
                                )}
                                onClick={() => setStatusFilter(option.value)}
                            >
                                {option.label}
                            </button>
                        ))}
                    </div>
                </div>
            </Card>

            {/* Orders List */}
            <div className="min-h-[200px]">
                {loading ? (
                    <div className="flex flex-col gap-3">
                        {[1, 2, 3, 4, 5].map(i => (
                            <div key={i} className="h-20 rounded-md bg-bg-tertiary animate-pulse" />
                        ))}
                    </div>
                ) : filteredOrders.length > 0 ? (
                    <div className="flex flex-col gap-3">
                        {filteredOrders.map((order) => (
                            <Card key={order.id} className="px-5! py-4!" hoverable>
                                <div className="flex items-center justify-between mb-3">
                                    <div className="flex items-center gap-3">
                                        <span className="text-lg font-bold text-primary">#{order.order_number}</span>
                                        <span className={cn(
                                            'px-2.5 py-1 rounded-full text-xs font-medium',
                                            order.is_delivery ? 'bg-primary/10 text-primary' : 'bg-accent/10 text-accent'
                                        )}>
                                            {order.is_delivery ? '🚚 Entrega' : '🏪 Balcão'}
                                        </span>
                                        {order.customer_phone && (
                                            <span className="flex items-center justify-center w-6 h-6 bg-[rgba(37,211,102,0.15)] text-[#25D366] rounded-full text-xs" title="Cliente com WhatsApp">
                                                <FaWhatsapp />
                                            </span>
                                        )}
                                    </div>
                                    <div className="flex items-center gap-3">
                                        <StatusBadge
                                            status={order.status as OrderStatus}
                                            size="md"
                                            showIcon
                                            pulse={order.status === 'pending'}
                                        />
                                        <div className="relative">
                                            <button
                                                className="w-8 h-8 flex items-center justify-center bg-transparent border-none rounded-md text-text-secondary cursor-pointer transition-all duration-fast hover:bg-bg-tertiary hover:text-text-primary"
                                                onClick={() => setShowDropdown(showDropdown === order.id ? null : order.id)}
                                            >
                                                <FiMoreVertical />
                                            </button>
                                            {showDropdown === order.id && (
                                                <div className="absolute top-full right-0 mt-1 min-w-[180px] bg-bg-card border border-border rounded-md shadow-lg z-dropdown animate-[fadeInDown_0.15s_ease]">
                                                    <Link href={`/pedidos/${order.id}`} className="flex items-center gap-2.5 w-full px-3.5 py-2.5 bg-transparent border-none text-text-secondary text-sm text-left cursor-pointer transition-all duration-fast hover:bg-bg-tertiary hover:text-text-primary">
                                                        <FiEye /> Ver Detalhes
                                                    </Link>
                                                    <Link href={`/pedidos/${order.id}/editar`} className="flex items-center gap-2.5 w-full px-3.5 py-2.5 bg-transparent border-none text-text-secondary text-sm text-left cursor-pointer transition-all duration-fast hover:bg-bg-tertiary hover:text-text-primary">
                                                        <FiEdit /> Editar
                                                    </Link>
                                                    {order.customer_phone && (
                                                        <button
                                                            className="flex items-center gap-2.5 w-full px-3.5 py-2.5 bg-transparent border-none text-[#25D366] text-sm text-left cursor-pointer transition-all duration-fast hover:bg-[rgba(37,211,102,0.1)]"
                                                            onClick={() => {
                                                                sendWhatsAppNotification(order, order.status || 'pending');
                                                                setShowDropdown(null);
                                                            }}
                                                        >
                                                            <FaWhatsapp /> Enviar WhatsApp
                                                        </button>
                                                    )}
                                                    <div className="h-px bg-border my-1" />
                                                    <button
                                                        className="flex items-center gap-2.5 w-full px-3.5 py-2.5 bg-transparent border-none text-error text-sm text-left cursor-pointer transition-all duration-fast hover:bg-error/10"
                                                        onClick={() => deleteOrder(order.id)}
                                                    >
                                                        <FiTrash2 /> Excluir
                                                    </button>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>

                                <div className="flex justify-between items-start mb-3 pb-3 border-b border-border max-md:flex-col max-md:gap-3">
                                    <div className="flex flex-col gap-1">
                                        <span className="font-medium">{order.customer_name}</span>
                                        {order.customer_phone && (
                                            <span className="text-sm text-text-secondary">{order.customer_phone}</span>
                                        )}
                                    </div>

                                    <div className="flex gap-8 max-md:w-full max-md:justify-between">
                                        <div className="flex flex-col items-end gap-1 max-md:items-start">
                                            <span className="text-xs text-text-muted uppercase">Pagamento</span>
                                            <span className="flex items-center gap-2 text-sm">
                                                <PaymentMethodBadge
                                                    method={order.payment_method as PaymentMethod}
                                                    size="xs"
                                                />
                                                <StatusBadge
                                                    status={order.payment_status === 'paid' ? 'paid' : 'pending'}
                                                    size="xs"
                                                    showIcon={false}
                                                />
                                                {order.payment_status === 'pending' && (
                                                    <button
                                                        className="px-2.5 py-1 ml-1.5 bg-accent border-none rounded-full text-white text-[0.7rem] font-medium cursor-pointer transition-all duration-fast hover:opacity-90 hover:-translate-y-px"
                                                        onClick={(e) => {
                                                            e.stopPropagation();
                                                            updatePaymentStatus(order.id);
                                                        }}
                                                    >
                                                        Recebido
                                                    </button>
                                                )}
                                            </span>
                                        </div>
                                        <div className="flex flex-col items-end gap-1 max-md:items-start">
                                            <span className="text-xs text-text-muted uppercase">Total</span>
                                            <span className="text-lg font-bold text-accent">{formatCurrency(order.total)}</span>
                                        </div>
                                    </div>
                                </div>

                                <div className="flex items-center justify-between max-md:flex-col max-md:gap-3 max-md:items-stretch">
                                    <span className="flex items-center gap-1.5 text-sm text-text-muted">
                                        <FiClock /> {formatDateTime(order.created_at || new Date().toISOString())}
                                    </span>

                                    <div className="flex gap-2 max-md:justify-end">
                                        {order.status === 'pending' && (
                                            <button
                                                className="px-4 py-2 bg-primary border-none rounded-md text-white text-sm font-medium cursor-pointer transition-all duration-fast hover:opacity-90 hover:-translate-y-px"
                                                onClick={() => handleStatusChangeWithNotification(order, 'preparing')}
                                            >
                                                Iniciar Preparo
                                            </button>
                                        )}
                                        {order.status === 'preparing' && (
                                            <button
                                                className="px-4 py-2 bg-primary border-none rounded-md text-white text-sm font-medium cursor-pointer transition-all duration-fast hover:opacity-90 hover:-translate-y-px"
                                                onClick={() => handleStatusChangeWithNotification(order, 'ready')}
                                            >
                                                Marcar Pronto
                                            </button>
                                        )}
                                        {order.status === 'ready' && order.is_delivery && (
                                            <button
                                                className="px-4 py-2 bg-primary border-none rounded-md text-white text-sm font-medium cursor-pointer transition-all duration-fast hover:opacity-90 hover:-translate-y-px"
                                                onClick={() => handleStatusChangeWithNotification(order, 'delivering')}
                                            >
                                                Saiu para Entrega
                                            </button>
                                        )}
                                        {((order.status === 'ready' && !order.is_delivery) || order.status === 'delivering') && (
                                            <button
                                                className="px-4 py-2 bg-accent border-none rounded-md text-white text-sm font-medium cursor-pointer transition-all duration-fast hover:opacity-90 hover:-translate-y-px"
                                                onClick={() => handleStatusChangeWithNotification(order, 'delivered')}
                                            >
                                                Finalizar
                                            </button>
                                        )}
                                    </div>
                                </div>
                            </Card>
                        ))}

                        {/* Botão Carregar Mais */}
                        {hasMore && (
                            <div className="flex justify-center pt-4">
                                <Button
                                    variant="outline"
                                    onClick={loadMore}
                                    className="min-w-[200px]"
                                >
                                    Carregar Mais Pedidos
                                </Button>
                            </div>
                        )}
                    </div>
                ) : (
                    <div className="flex flex-col items-center justify-center py-15 px-5 text-center">
                        <span className="text-6xl mb-4">📋</span>
                        <h3 className="text-xl mb-2">Nenhum pedido encontrado</h3>
                        <p className="text-text-secondary mb-5">Crie um novo pedido para começar</p>
                        <Link href="/pedidos/novo">
                            <Button leftIcon={<FiPlus />}>Novo Pedido</Button>
                        </Link>
                    </div>
                )}
            </div>

            {/* WhatsApp Notification Modal */}
            {showWhatsAppModal && (
                <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-1000 animate-[fadeIn_0.2s_ease]" onClick={() => setShowWhatsAppModal(null)}>
                    <div className="bg-bg-card rounded-lg p-6 max-w-[400px] w-[90%] animate-[scaleIn_0.2s_ease]" onClick={e => e.stopPropagation()}>
                        <div className="flex items-center gap-3 mb-4">
                            <FaWhatsapp className="text-2xl text-[#25D366]" />
                            <h3 className="m-0 text-xl">Notificar Cliente?</h3>
                        </div>
                        <p className="text-text-secondary mb-6 leading-relaxed">
                            Deseja enviar uma notificação via WhatsApp para <strong className="text-text-primary">{showWhatsAppModal.customer_name}</strong> sobre a atualização do pedido?
                        </p>
                        <div className="flex gap-3 justify-end max-[480px]:flex-col-reverse">
                            <Button
                                variant="outline"
                                onClick={() => {
                                    if (pendingStatusForModal) {
                                        updateOrderStatus(showWhatsAppModal.id, pendingStatusForModal, false);
                                    }
                                }}
                            >
                                Não Notificar
                            </Button>
                            <Button
                                leftIcon={<FaWhatsapp />}
                                onClick={() => {
                                    if (pendingStatusForModal) {
                                        updateOrderStatus(showWhatsAppModal.id, pendingStatusForModal, true);
                                    }
                                }}
                                style={{ background: '#25D366' }}
                            >
                                Enviar WhatsApp
                            </Button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
    FiPlus,
    FiEdit2,
    FiTrash2,
    FiSearch,
    FiMove,
    FiTag
} from 'react-icons/fi';
import Image from 'next/image';
import {
    DndContext,
    closestCenter,
    KeyboardSensor,
    PointerSensor,
    TouchSensor,
    useSensor,
    useSensors,
    DragEndEvent,
} from '@dnd-kit/core';
import {
    arrayMove,
    SortableContext,
    sortableKeyboardCoordinates,
    useSortable,
    rectSortingStrategy,
} from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import Input from '@/components/ui/Input';
import ImageUpload from '@/components/ui/ImageUpload';
import { LimitWarning } from '@/components/ui/UpgradePrompt';
import { useToast } from '@/components/ui/Toast';
import { useAuth } from '@/contexts/AuthContext';
import { useSubscription } from '@/contexts/SubscriptionContext';
import { supabase } from '@/lib/supabase';
import { db } from '@/lib/db';
import { formatCurrency } from '@/hooks/useFormatters';
import { cn } from '@/lib/utils';
import { useProductsCache, useCategoriesCache, useAddonsCache } from '@/hooks/useDataCache';
import { revalidateStoreMenu } from '@/app/actions/menu';
import * as dataAccess from '@/lib/dataAccess';
import type { CachedProductAddonGroup } from '@/types/db';

interface Category {
    id: string;
    name: string;
    icon: string;
    color: string;
}

interface Product {
    id: string;
    name: string;
    description: string | null;
    price: number;
    category_id: string;
    available: boolean;
    display_order: number;
    image_url: string | null;
    promo_enabled: boolean;
    promo_value: number;
    promo_type: 'value' | 'percentage';
}

interface AddonGroup {
    id: string;
    name: string;
    description: string | null;
    required: boolean;
}

function SortableProductCard({
    product,
    category,
    formatCurrency,
    onEdit,
    onDelete,
    onToggleAvailability
}: {
    product: Product;
    category: Category | undefined;
    formatCurrency: (value: number) => string;
    onEdit: () => void;
    onDelete: () => void;
    onToggleAvailability: () => void;
}) {
    const {
        attributes,
        listeners,
        setNodeRef,
        transform,
        transition,
        isDragging,
    } = useSortable({ id: product.id });

    const style: React.CSSProperties = {
        transform: CSS.Transform.toString(transform),
        transition,
        opacity: isDragging ? 0.5 : 1,
        zIndex: isDragging ? 1000 : 'auto',
    };

    return (
        <div ref={setNodeRef} style={style}>
            <Card className={cn(
                'p-4! flex flex-col relative transition-all duration-200',
                !product.available && 'opacity-60',
                isDragging && 'shadow-[0_8px_24px_rgba(0,0,0,0.3)] border-primary'
            )}>
                <div
                    className="absolute top-2 right-2 flex items-center justify-center w-6 h-6 text-text-muted opacity-0 cursor-grab transition-all duration-fast rounded-sm z-10 touch-none select-none hover:text-primary hover:bg-primary/10 active:cursor-grabbing group-hover:opacity-100"
                    {...attributes}
                    {...listeners}
                    title="Arraste para reordenar"
                    style={{ opacity: 1 }}
                >
                    <FiMove size={14} />
                </div>
                <div className="flex gap-4">
                    {product.image_url && (
                        <div className="relative shrink-0 w-20 h-20 rounded-md overflow-hidden bg-bg-tertiary">
                            <Image
                                src={product.image_url}
                                alt={product.name}
                                fill
                                className="object-cover"
                                sizes="80px"
                            />
                        </div>
                    )}
                    <div className="flex-1 min-w-0 flex flex-col">
                        <div className="flex justify-between items-center mb-3">
                            <span className="text-xs text-text-muted">
                                {category?.icon} {category?.name}
                            </span>
                            <button
                                className={cn(
                                    'px-2.5 py-1 border-none rounded-full text-[0.7rem] font-medium cursor-pointer transition-all duration-fast',
                                    product.available ? 'bg-accent/10 text-accent' : 'bg-error/10 text-error'
                                )}
                                onClick={onToggleAvailability}
                            >
                                {product.available ? 'Disponível' : 'Indisponível'}
                            </button>
                        </div>
                        <div className="flex justify-between items-start mb-1">
                            <h3 className="text-base font-semibold truncate flex-1">{product.name}</h3>
                            {product.promo_enabled && (
                                <span className="ml-2 px-1.5 py-0.5 bg-success/10 text-success text-[10px] font-bold rounded flex items-center gap-0.5">
                                    <FiTag size={10} /> Promo
                                </span>
                            )}
                        </div>
                        {product.description && (
                            <p className="text-[0.8125rem] text-text-secondary mb-3 flex-1 line-clamp-2 overflow-hidden">{product.description}</p>
                        )}
                        <div className="flex justify-between items-center mt-auto pt-3 border-t border-border">
                            <span className="text-lg font-bold text-primary">{formatCurrency(product.price)}</span>
                            <div className="flex gap-1">
                                <button className="w-8 h-8 flex items-center justify-center bg-transparent border-none rounded-md text-text-secondary cursor-pointer transition-all duration-fast hover:bg-bg-tertiary hover:text-text-primary" onClick={onEdit}>
                                    <FiEdit2 />
                                </button>
                                <button
                                    className="w-8 h-8 flex items-center justify-center bg-transparent border-none rounded-md text-text-secondary cursor-pointer transition-all duration-fast hover:bg-error/10 hover:text-error"
                                    onClick={onDelete}
                                >
                                    <FiTrash2 />
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </Card>
        </div>
    );
}

export default function ProdutosPage() {
    const { user } = useAuth();
    const { getLimit, isWithinLimit } = useSubscription();

    // Novo sistema de cache: Economia de ~50% nas consultas
    const {
        products: cachedProducts,
        loading: productsLoading,
        refetch: refetchProducts
    } = useProductsCache();

    const {
        categories: cachedCategories,
        loading: categoriesLoading
    } = useCategoriesCache();

    const {
        addonGroups: cachedAddonGroups,
        loading: addonsLoading
    } = useAddonsCache();

    const [categories, setCategories] = useState<Category[]>([]);
    const [products, setProducts] = useState<Product[]>([]);
    const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [loading, setLoading] = useState(true);

    // Sincronizar estado local com cache
    useEffect(() => {
        if (cachedProducts) setProducts(cachedProducts);
    }, [cachedProducts]);

    useEffect(() => {
        if (cachedCategories) setCategories(cachedCategories);
    }, [cachedCategories]);

    useEffect(() => {
        setLoading(productsLoading || categoriesLoading || addonsLoading);
    }, [productsLoading, categoriesLoading, addonsLoading]);

    const [showProductModal, setShowProductModal] = useState(false);
    const [editingProduct, setEditingProduct] = useState<Product | null>(null);
    const [productForm, setProductForm] = useState({
        name: '',
        description: '',
        price: '',
        category_id: '',
        available: true,
        image_url: null as string | null,
        promo_enabled: false,
        promo_value: '',
        promo_type: 'percentage' as 'value' | 'percentage'
    });
    const [saving, setSaving] = useState(false);

    const [addonGroups, setAddonGroups] = useState<AddonGroup[]>([]);
    const [selectedAddonGroups, setSelectedAddonGroups] = useState<string[]>([]);

    const saveTimeoutRef = useRef<NodeJS.Timeout | null>(null);
    const [isDragging, setIsDragging] = useState(false);

    const productsLimit = getLimit('products');
    const isAtLimit = !isWithinLimit('products', products.length);
    const toast = useToast();

    const sensors = useSensors(
        useSensor(PointerSensor, { activationConstraint: { distance: 8 } }),
        useSensor(TouchSensor, { activationConstraint: { delay: 200, tolerance: 5 } }),
        useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
    );

    useEffect(() => {
        if (isDragging) {
            const preventScroll = (e: TouchEvent) => e.preventDefault();
            document.body.style.overflow = 'hidden';
            document.body.style.touchAction = 'none';
            document.addEventListener('touchmove', preventScroll, { passive: false });
            return () => {
                document.body.style.overflow = '';
                document.body.style.touchAction = '';
                document.removeEventListener('touchmove', preventScroll);
            };
        }
    }, [isDragging]);

    useEffect(() => {
        if (cachedAddonGroups) setAddonGroups(cachedAddonGroups);
    }, [cachedAddonGroups]);



    const filteredProducts = products.filter(product => {
        const matchesSearch = product.name.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesCategory = !selectedCategory || product.category_id === selectedCategory;
        return matchesSearch && matchesCategory;
    });

    const getCategoryById = (id: string) => categories.find(c => c.id === id);

    const handleDragStart = useCallback(() => setIsDragging(true), []);

    const handleDragEnd = useCallback((event: DragEndEvent) => {
        setIsDragging(false);
        const { active, over } = event;
        if (over && active.id !== over.id) {
            setProducts((items) => {
                const oldIndex = items.findIndex(item => item.id === active.id);
                const newIndex = items.findIndex(item => item.id === over.id);
                const newItems = arrayMove(items, oldIndex, newIndex);
                if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
                saveTimeoutRef.current = setTimeout(async () => {
                    try {
                        const updates = newItems.map((item, index) => ({
                            id: item.id,
                            display_order: index
                        }));
                        await dataAccess.bulkUpdateProducts(updates);
                        revalidateStoreMenu();
                    } catch (error) {
                        console.error('Failed to save product order:', error);
                    }
                }, 500);
                return newItems;
            });
        }
    }, []);

    const openProductModal = async (product?: Product) => {
        if (!product && isAtLimit) {
            alert(`Limite de ${productsLimit} produtos atingido! Faça upgrade do seu plano para adicionar mais.`);
            return;
        }
        if (product) {
            setEditingProduct(product);
            setProductForm({
                name: product.name,
                description: product.description || '',
                price: product.price.toString(),
                category_id: product.category_id,
                available: product.available,
                image_url: product.image_url,
                promo_enabled: product.promo_enabled ?? false,
                promo_value: (product.promo_value ?? 0).toString(),
                promo_type: (product.promo_type as 'value' | 'percentage') ?? 'percentage'
            });
            const productGroups = (cachedProducts as any)?.find((p: any) => p.id === product.id)?.addon_groups || [];
            // Actually, the cache hook might not have joined these in the products list yet if we only updated db.ts
            // But we have useAddonsCache which provides addonGroups and their associations.
            // Let's use the raw product_addon_groups from the useAddonsCache result.
            const selectedIds = (cachedAddonGroups as any)?.filter((g: any) => g.productId === product.id).map((g: any) => g.id) || [];
            // Wait, useAddonsCache's getProductAddons returns joined data.
            // For the modal, we need selected IDs.
            // I'll just use the Dexie database directly if needed, or better, the dataAccess.
            const selections = await db.product_addon_groups.where('product_id').equals(product.id).toArray();
            setSelectedAddonGroups(selections.map((s: CachedProductAddonGroup) => s.group_id));
        } else {
            setEditingProduct(null);
            setProductForm({
                name: '',
                description: '',
                price: '',
                category_id: categories[0]?.id || '',
                available: true,
                image_url: null,
                promo_enabled: false,
                promo_value: '',
                promo_type: 'percentage'
            });
            setSelectedAddonGroups([]);
        }
        setShowProductModal(true);
    };

    const closeProductModal = () => {
        setShowProductModal(false);
        setEditingProduct(null);
        setSelectedAddonGroups([]);
    };

    const handleSaveProduct = async () => {
        if (!user || !productForm.name || !productForm.price || !productForm.category_id) return;
        setSaving(true);
        try {
            const productData = {
                user_id: user.id,
                name: productForm.name,
                description: productForm.description || null,
                price: parseFloat(productForm.price),
                category_id: productForm.category_id,
                available: productForm.available,
                image_url: productForm.image_url,
                promo_enabled: productForm.promo_enabled,
                promo_value: parseFloat(productForm.promo_value) || 0,
                promo_type: productForm.promo_type
            };
            let productId: string;
            if (editingProduct) {
                await dataAccess.updateProduct(editingProduct.id, productData);
                productId = editingProduct.id;
            } else {
                const maxOrder = products.length > 0 ? Math.max(...products.map(p => p.display_order || 0)) : -1;
                // Note: dataAccess.createProduct handles local record creation and pending action
                productId = (productData as any).id || crypto.randomUUID();
                await dataAccess.createProduct({ ...productData, id: productId, display_order: maxOrder + 1 });
            }
            // Use the new DAL implementation for offline-first relationship updates
            await dataAccess.updateProductAddonGroups(productId, selectedAddonGroups);
            toast.success(editingProduct ? 'Produto atualizado!' : 'Produto criado!');
            revalidateStoreMenu();
            closeProductModal();
        } catch (error) {
            console.error('Error saving product:', error);
            toast.error('Erro ao salvar produto');
        } finally {
            setSaving(false);
        }
    };

    const deleteProduct = async (id: string) => {
        if (!confirm('Tem certeza que deseja excluir este produto?')) return;
        try {
            const product = products.find(p => p.id === id);
            if (product?.image_url) {
                const urlParts = product.image_url.split('product-images/');
                if (urlParts.length >= 2) {
                    await supabase.storage.from('product-images').remove([urlParts[1]]);
                }
            }
            await dataAccess.deleteProduct(id);
            toast.success('Produto excluído!');
            revalidateStoreMenu();
        } catch (error) {
            console.error('Error deleting product:', error);
            toast.error('Erro ao excluir produto');
        }
    };

    const toggleAvailability = async (product: Product) => {
        try {
            await dataAccess.updateProduct(product.id, { available: !product.available });
            revalidateStoreMenu();
        } catch (error) {
            console.error('Error toggling availability:', error);
        }
    };

    return (
        <div className="max-w-[1400px] mx-auto overscroll-contain">
            {/* Header */}
            <div className="flex items-start justify-between mb-8 gap-5 max-md:flex-col">
                <div>
                    <h1 className="text-[2rem] font-bold mb-2">Produtos</h1>
                    <p className="text-text-secondary">Gerencie seu cardápio (arraste para reordenar)</p>
                </div>
                <Button leftIcon={<FiPlus />} onClick={() => openProductModal()} disabled={isAtLimit}>
                    Novo Produto
                </Button>
            </div>

            <LimitWarning resource="produtos" current={products.length} limit={productsLimit} requiredPlan="Avançado" />

            {/* Filters */}
            <Card className="mb-6 px-5! py-4!">
                <div className="flex flex-col gap-4">
                    <div className="max-w-[400px]">
                        <Input placeholder="Buscar produto..." leftIcon={<FiSearch />} value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                    </div>
                    <div className="flex flex-wrap gap-2">
                        <button className={cn('px-4 py-2 bg-bg-tertiary border border-border rounded-full text-text-secondary text-sm cursor-pointer transition-all duration-fast hover:border-border-light hover:text-text-primary', !selectedCategory && 'bg-primary border-primary text-white')} onClick={() => setSelectedCategory(null)}>
                            Todos
                        </button>
                        {categories.map((category) => (
                            <button key={category.id} className={cn('px-4 py-2 bg-bg-tertiary border border-border rounded-full text-text-secondary text-sm cursor-pointer transition-all duration-fast hover:border-border-light hover:text-text-primary', selectedCategory === category.id && 'bg-primary border-primary text-white')} onClick={() => setSelectedCategory(category.id)}>
                                {category.icon} {category.name}
                            </button>
                        ))}
                    </div>
                </div>
            </Card>

            {/* Products Grid */}
            {loading ? (
                <div className="grid grid-cols-3 gap-4 max-[1024px]:grid-cols-2 max-md:grid-cols-1 overscroll-y-none">
                    {[1, 2, 3, 4, 5, 6].map(i => (
                        <div key={i} className="h-40 rounded-xl bg-bg-tertiary animate-pulse" />
                    ))}
                </div>
            ) : filteredProducts.length > 0 ? (
                <DndContext sensors={sensors} collisionDetection={closestCenter} onDragStart={handleDragStart} onDragEnd={handleDragEnd}>
                    <SortableContext items={filteredProducts.map(p => p.id)} strategy={rectSortingStrategy}>
                        <div className="grid grid-cols-3 gap-4 max-[1024px]:grid-cols-2 max-md:grid-cols-1 overscroll-y-none">
                            {filteredProducts.map((product) => (
                                <SortableProductCard key={product.id} product={product} category={getCategoryById(product.category_id)} formatCurrency={formatCurrency} onEdit={() => openProductModal(product)} onDelete={() => deleteProduct(product.id)} onToggleAvailability={() => toggleAvailability(product)} />
                            ))}
                        </div>
                    </SortableContext>
                </DndContext>
            ) : (
                <div className="flex flex-col items-center justify-center py-15 px-5 text-center">
                    <span className="text-6xl mb-4">🍔</span>
                    <h3 className="text-xl mb-2">Nenhum produto encontrado</h3>
                    <p className="text-text-secondary mb-5">Adicione produtos ao seu cardápio</p>
                    <Button leftIcon={<FiPlus />} onClick={() => openProductModal()}>Novo Produto</Button>
                </div>
            )}

            {/* Product Modal */}
            {showProductModal && (
                <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-modal p-6 animate-[fadeIn_0.15s_ease]" onClick={closeProductModal}>
                    <div className="w-full max-w-[500px] max-h-[90vh] overflow-y-auto bg-bg-card rounded-xl border border-border p-7 animate-[scaleIn_0.15s_ease] scrollbar-thin" onClick={(e) => e.stopPropagation()}>
                        <h2 className="text-xl font-semibold mb-6">{editingProduct ? 'Editar Produto' : 'Novo Produto'}</h2>

                        <div className="flex flex-col gap-4 mb-6">
                            <div className="flex flex-col gap-1.5">
                                <label className="text-sm font-medium text-text-secondary">Foto do Produto</label>
                                <ImageUpload value={productForm.image_url} onChange={(url) => setProductForm({ ...productForm, image_url: url })} folder={user?.id} placeholder="Adicionar foto do produto" />
                            </div>

                            <Input label="Nome" placeholder="Nome do produto" value={productForm.name} onChange={(e) => setProductForm({ ...productForm, name: e.target.value })} required />

                            <div className="grid grid-cols-2 gap-4 max-md:grid-cols-1">
                                <div className="flex flex-col gap-1.5">
                                    <label className="text-sm font-medium text-text-secondary">Categoria</label>
                                    <select className="h-12 px-4 bg-bg-tertiary border-2 border-border rounded-md text-text-primary text-[0.9375rem] focus:border-primary focus:outline-none" value={productForm.category_id} onChange={(e) => setProductForm({ ...productForm, category_id: e.target.value })}>
                                        {categories.map((cat) => (<option key={cat.id} value={cat.id}>{cat.icon} {cat.name}</option>))}
                                    </select>
                                </div>
                                <Input label="Preço" type="number" placeholder="0,00" value={productForm.price} onChange={(e) => setProductForm({ ...productForm, price: e.target.value })} required />
                            </div>

                            <div className="flex flex-col gap-1.5">
                                <label className="text-sm font-medium text-text-secondary">Descrição (opcional)</label>
                                <textarea className="px-4 py-3 bg-bg-tertiary border-2 border-border rounded-md text-text-primary text-[0.9375rem] resize-y min-h-20 focus:border-primary focus:outline-none" placeholder="Descrição do produto" value={productForm.description} onChange={(e) => setProductForm({ ...productForm, description: e.target.value })} rows={3} />
                            </div>

                            {addonGroups.length > 0 && (
                                <div className="flex flex-col gap-1.5">
                                    <label className="text-sm font-medium text-text-secondary">Grupos de Adicionais</label>
                                    <p className="text-[0.8rem] text-text-muted mb-1">Selecione quais adicionais este produto pode ter</p>
                                    <div className="flex flex-wrap gap-2 mt-1">
                                        {addonGroups.map((group) => (
                                            <label key={group.id} className={cn('flex items-center gap-2 px-3.5 py-2 bg-bg-tertiary border-2 border-border rounded-md cursor-pointer transition-all duration-fast text-sm hover:border-primary', selectedAddonGroups.includes(group.id) && 'bg-primary/10 border-primary')}>
                                                <input type="checkbox" className="w-4 h-4 accent-primary" checked={selectedAddonGroups.includes(group.id)} onChange={(e) => {
                                                    if (e.target.checked) setSelectedAddonGroups([...selectedAddonGroups, group.id]);
                                                    else setSelectedAddonGroups(selectedAddonGroups.filter(id => id !== group.id));
                                                }} />
                                                <span>{group.name}</span>
                                                {group.required && <span className="text-[0.7rem] text-warning ml-1">(Obrigatório)</span>}
                                            </label>
                                        ))}
                                    </div>
                                </div>
                            )}

                            <label className="flex items-center gap-2.5 cursor-pointer">
                                <input type="checkbox" className="w-[18px] h-[18px] accent-primary" checked={productForm.available} onChange={(e) => setProductForm({ ...productForm, available: e.target.checked })} />
                                Produto disponível
                            </label>

                            <div className="mt-2 p-4 bg-bg-tertiary rounded-lg border border-border">
                                <div className="flex items-center justify-between mb-4">
                                    <div className="flex items-center gap-2">
                                        <FiTag className={cn(productForm.promo_enabled ? "text-success" : "text-text-muted")} />
                                        <span className="text-sm font-semibold">Promoção</span>
                                    </div>
                                    <button
                                        type="button"
                                        onClick={() => setProductForm({ ...productForm, promo_enabled: !productForm.promo_enabled })}
                                        className={cn(
                                            "relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none",
                                            productForm.promo_enabled ? "bg-success" : "bg-bg-card border border-border"
                                        )}
                                    >
                                        <span
                                            className={cn(
                                                "inline-block h-4 w-4 transform rounded-full bg-white transition-transform",
                                                productForm.promo_enabled ? "translate-x-6" : "translate-x-1"
                                            )}
                                        />
                                    </button>
                                </div>

                                {productForm.promo_enabled && (
                                    <div className="grid grid-cols-2 gap-4 animate-[fadeIn_0.2s_ease]">
                                        <div className="flex flex-col gap-1.5">
                                            <label className="text-xs font-medium text-text-secondary">Tipo</label>
                                            <select
                                                className="h-10 px-3 bg-bg-card border border-border rounded text-sm text-text-primary focus:border-primary focus:outline-none"
                                                value={productForm.promo_type}
                                                onChange={(e) => setProductForm({ ...productForm, promo_type: e.target.value as 'value' | 'percentage' })}
                                            >
                                                <option value="percentage">Porcentagem (%)</option>
                                                <option value="value">Valor Fixo (R$)</option>
                                            </select>
                                        </div>
                                        <Input
                                            label={productForm.promo_type === 'percentage' ? "Porcentagem (%)" : "Desconto (R$)"}
                                            type="number"
                                            placeholder="0"
                                            value={productForm.promo_value}
                                            onChange={(e) => setProductForm({ ...productForm, promo_value: e.target.value })}
                                            className="h-10!"
                                        />
                                    </div>
                                )}
                            </div>
                        </div>

                        <div className="flex justify-end gap-3">
                            <button className="px-4 py-2 bg-transparent border-none text-text-secondary cursor-pointer hover:text-text-primary" onClick={closeProductModal}>Cancelar</button>
                            <Button onClick={handleSaveProduct} isLoading={saving}>{editingProduct ? 'Salvar' : 'Criar Produto'}</Button>
                        </div>
                    </div>
                </div>
            )
            }
        </div >
    );
}

'use client';

import React, { useState, useEffect, useMemo } from 'react';
import {
    FiCalendar,
    FiDownload,
    FiTrendingUp,
    FiTrendingDown,
    FiShoppingBag,
    FiDollarSign,
    FiClock,
    FiTruck,
    FiBarChart2,
    FiPieChart,
    FiUsers,
    FiPackage,
    FiActivity,
    FiFileText
} from 'react-icons/fi';
import { BsCash } from 'react-icons/bs';
import {
    LineChart,
    Line,
    AreaChart,
    Area,
    BarChart,
    Bar,
    PieChart,
    Pie,
    Cell,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
    ResponsiveContainer
} from 'recharts';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import UpgradePrompt from '@/components/ui/UpgradePrompt';
import { useToast } from '@/components/ui/Toast';
import { useAuth } from '@/contexts/AuthContext';
import { useSubscription } from '@/contexts/SubscriptionContext';
import { supabase } from '@/lib/supabase';
import { formatCurrency, formatCurrencyShort } from '@/hooks/useFormatters';
import styles from './page.module.css';
import dynamic from 'next/dynamic';
import RelatorioPDFCompleto from '@/components/reports/RelatorioPDFCompleto';

const PDFDownloadLink = dynamic(
    () => import('@react-pdf/renderer').then((mod) => mod.PDFDownloadLink),
    { ssr: false }
);


type PeriodType = 'today' | 'week' | 'month' | '30days' | 'custom';
type ComparisonType = 'previous' | 'lastWeek' | 'lastMonth' | 'lastYear';

interface Order {
    id: string;
    order_number: number;
    customer_name: string;
    status: string;
    payment_method: string;
    payment_status: string;
    total: number;
    is_delivery: boolean;
    created_at: string;
}

interface OrderItem {
    id: string;
    order_id: string;
    product_id: string;
    product_name: string;
    quantity: number;
    unit_price: number;
    total: number;
}

interface Category {
    id: string;
    name: string;
    icon: string;
    color: string;
}

interface Product {
    id: string;
    name: string;
    category_id: string;
}

interface ReportStats {
    totalRevenue: number;
    totalOrders: number;
    averageTicket: number;
    previousRevenue: number;
    previousOrders: number;
    deliveryCount: number;
    pickupCount: number;
    byPaymentMethod: { [key: string]: number };
    byStatus: { [key: string]: number };
    byHour: { [key: number]: number };
    byDay: { [key: string]: number };
    topProducts: { name: string; quantity: number; revenue: number }[];
    byCategory: { categoryId: string; name: string; icon: string; color: string; total: number }[];
    // Comparison data
    comparisonRevenue: number;
    comparisonOrders: number;
    comparisonByDay: { [key: string]: number };
}

// Colors for charts
const CHART_COLORS = ['#ff6b35', '#00b894', '#0984e3', '#fdcb6e', '#e84393', '#6c5ce7', '#00cec9', '#fd79a8'];
const PAYMENT_COLORS: Record<string, string> = {
    money: '#00b894',
    pix: '#0984e3',
    credit: '#fdcb6e',
    debit: '#e84393'
};

export default function RelatoriosPage() {
    const { user, userSettings } = useAuth();
    const { canAccess, plan } = useSubscription();
    const toast = useToast();
    const [period, setPeriod] = useState<PeriodType>('month');
    const [comparison, setComparison] = useState<ComparisonType>('previous');
    const [customStartDate, setCustomStartDate] = useState('');
    const [customEndDate, setCustomEndDate] = useState('');
    const [loading, setLoading] = useState(true);
    const [isClient, setIsClient] = useState(false);
    const [stats, setStats] = useState<ReportStats>({
        totalRevenue: 0,
        totalOrders: 0,
        averageTicket: 0,
        previousRevenue: 0,
        previousOrders: 0,
        deliveryCount: 0,
        pickupCount: 0,
        byPaymentMethod: {},
        byStatus: {},
        byHour: {},
        byDay: {},
        topProducts: [],
        byCategory: [],
        comparisonRevenue: 0,
        comparisonOrders: 0,
        comparisonByDay: {}
    });

    // Calculate date range based on selected period
    const dateRange = useMemo(() => {
        const now = new Date();
        let startDate: Date;
        let endDate = new Date(now);
        let previousStartDate: Date;
        let previousEndDate: Date;
        let comparisonStartDate: Date;
        let comparisonEndDate: Date;

        switch (period) {
            case 'today':
                startDate = new Date(now);
                startDate.setHours(0, 0, 0, 0);
                endDate.setHours(23, 59, 59, 999);
                previousStartDate = new Date(startDate);
                previousStartDate.setDate(previousStartDate.getDate() - 1);
                previousEndDate = new Date(previousStartDate);
                previousEndDate.setHours(23, 59, 59, 999);
                break;
            case 'week':
                startDate = new Date(now);
                startDate.setDate(now.getDate() - 7);
                startDate.setHours(0, 0, 0, 0);
                previousStartDate = new Date(startDate);
                previousStartDate.setDate(previousStartDate.getDate() - 7);
                previousEndDate = new Date(startDate);
                previousEndDate.setDate(previousEndDate.getDate() - 1);
                previousEndDate.setHours(23, 59, 59, 999);
                break;
            case 'month':
                startDate = new Date(now.getFullYear(), now.getMonth(), 1);
                previousStartDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
                previousEndDate = new Date(now.getFullYear(), now.getMonth(), 0);
                previousEndDate.setHours(23, 59, 59, 999);
                break;
            case '30days':
                startDate = new Date(now);
                startDate.setDate(now.getDate() - 30);
                startDate.setHours(0, 0, 0, 0);
                previousStartDate = new Date(startDate);
                previousStartDate.setDate(previousStartDate.getDate() - 30);
                previousEndDate = new Date(startDate);
                previousEndDate.setDate(previousEndDate.getDate() - 1);
                previousEndDate.setHours(23, 59, 59, 999);
                break;
            case 'custom':
                if (customStartDate && customEndDate) {
                    startDate = new Date(`${customStartDate}T00:00:00`);
                    endDate = new Date(`${customEndDate}T23:59:59.999`);
                    const diffDays = Math.ceil((endDate.getTime() - startDate.getTime()) / (1000 * 60 * 60 * 24));
                    previousEndDate = new Date(startDate);
                    previousEndDate.setDate(previousEndDate.getDate() - 1);
                    previousEndDate.setHours(23, 59, 59, 999);
                    previousStartDate = new Date(previousEndDate);
                    previousStartDate.setDate(previousStartDate.getDate() - diffDays + 1);
                    previousStartDate.setHours(0, 0, 0, 0);
                } else {
                    startDate = new Date(now.getFullYear(), now.getMonth(), 1);
                    previousStartDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
                    previousEndDate = new Date(now.getFullYear(), now.getMonth(), 0);
                }
                break;
            default:
                startDate = new Date(now.getFullYear(), now.getMonth(), 1);
                previousStartDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
                previousEndDate = new Date(now.getFullYear(), now.getMonth(), 0);
        }

        // Calculate comparison period based on comparison type
        switch (comparison) {
            case 'lastWeek':
                comparisonStartDate = new Date(startDate);
                comparisonStartDate.setDate(comparisonStartDate.getDate() - 7);
                comparisonEndDate = new Date(endDate);
                comparisonEndDate.setDate(comparisonEndDate.getDate() - 7);
                break;
            case 'lastMonth':
                comparisonStartDate = new Date(startDate);
                comparisonStartDate.setMonth(comparisonStartDate.getMonth() - 1);
                comparisonEndDate = new Date(endDate);
                comparisonEndDate.setMonth(comparisonEndDate.getMonth() - 1);
                break;
            case 'lastYear':
                comparisonStartDate = new Date(startDate);
                comparisonStartDate.setFullYear(comparisonStartDate.getFullYear() - 1);
                comparisonEndDate = new Date(endDate);
                comparisonEndDate.setFullYear(comparisonEndDate.getFullYear() - 1);
                break;
            default:
                comparisonStartDate = previousStartDate;
                comparisonEndDate = previousEndDate;
        }

        return { startDate, endDate, previousStartDate, previousEndDate, comparisonStartDate, comparisonEndDate };
    }, [period, customStartDate, customEndDate, comparison]);

    useEffect(() => {
        setIsClient(true);
    }, []);

    useEffect(() => {
        if (user) {
            fetchReportData();
        }
    }, [user, dateRange]);

    const fetchReportData = async () => {
        if (!user) return;

        setLoading(true);
        try {
            const { startDate, endDate, previousStartDate, previousEndDate, comparisonStartDate, comparisonEndDate } = dateRange;

            // Fetch current period orders
            const { data: currentOrders } = await supabase
                .from('orders')
                .select('*')
                .eq('user_id', user.id)
                .gte('created_at', startDate.toISOString())
                .lte('created_at', endDate.toISOString())
                .neq('status', 'cancelled');

            // Fetch previous period orders for comparison
            const { data: previousOrders } = await supabase
                .from('orders')
                .select('*')
                .eq('user_id', user.id)
                .gte('created_at', previousStartDate.toISOString())
                .lte('created_at', previousEndDate.toISOString())
                .neq('status', 'cancelled');

            // Fetch comparison period orders
            const { data: comparisonOrders } = await supabase
                .from('orders')
                .select('*')
                .eq('user_id', user.id)
                .gte('created_at', comparisonStartDate.toISOString())
                .lte('created_at', comparisonEndDate.toISOString())
                .neq('status', 'cancelled');

            // Fetch order items for current period
            const orderIds = currentOrders?.map(o => o.id) || [];
            let orderItems: OrderItem[] = [];
            if (orderIds.length > 0) {
                const { data: items } = await supabase
                    .from('order_items')
                    .select('*')
                    .in('order_id', orderIds);
                orderItems = items || [];
            }

            // Fetch categories
            const { data: categories } = await supabase
                .from('categories')
                .select('*')
                .eq('user_id', user.id);

            // Fetch products
            const { data: products } = await supabase
                .from('products')
                .select('*')
                .eq('user_id', user.id);

            // Calculate stats
            const orders = currentOrders || [];
            const prevOrders = previousOrders || [];
            const compOrders = comparisonOrders || [];
            const cats = categories || [];
            const prods = products || [];

            // OPTIMIZED: Single pass through orders for all metrics - O(n) instead of 4×O(n)
            // Initialize all tracking objects
            const byPaymentMethod: { [key: string]: number } = {};
            const byStatus: { [key: string]: number } = {};
            const byHour: { [key: number]: number } = {};
            const byDay: { [key: string]: number } = {};
            let totalRevenue = 0;
            let paidOrdersCount = 0;
            let deliveryCount = 0;
            let pickupCount = 0;

            // Single loop for all order metrics
            orders.forEach((o: Order) => {
                // byStatus - count all orders
                byStatus[o.status] = (byStatus[o.status] || 0) + 1;

                // byHour - count all orders
                const hour = new Date(o.created_at).getHours();
                byHour[hour] = (byHour[hour] || 0) + 1;

                // Delivery vs Pickup
                if (o.is_delivery) {
                    deliveryCount++;
                } else {
                    pickupCount++;
                }

                // Paid order specific metrics
                if (o.payment_status === 'paid') {
                    paidOrdersCount++;
                    totalRevenue += o.total;

                    // byPaymentMethod - only paid orders
                    byPaymentMethod[o.payment_method] = (byPaymentMethod[o.payment_method] || 0) + o.total;

                    // byDay - only paid orders
                    const day = new Date(o.created_at).toISOString().split('T')[0];
                    byDay[day] = (byDay[day] || 0) + o.total;
                }
            });

            // Previous period revenue - single reduce
            const previousRevenue = prevOrders.reduce((sum: number, o: Order) =>
                o.payment_status === 'paid' ? sum + o.total : sum, 0);

            // Comparison stats - optimized single loop
            const comparisonByDay: { [key: string]: number } = {};
            let comparisonRevenue = 0;
            compOrders.forEach((o: Order) => {
                if (o.payment_status === 'paid') {
                    comparisonRevenue += o.total;
                    const day = new Date(o.created_at).toISOString().split('T')[0];
                    comparisonByDay[day] = (comparisonByDay[day] || 0) + o.total;
                }
            });
            const comparisonOrdersCount = compOrders.length;

            // Top products
            const productSales: { [key: string]: { name: string; quantity: number; revenue: number } } = {};
            orderItems.forEach((item: OrderItem) => {
                const key = item.product_name;
                if (!productSales[key]) {
                    productSales[key] = { name: key, quantity: 0, revenue: 0 };
                }
                productSales[key].quantity += item.quantity;
                productSales[key].revenue += item.total;
            });
            const topProducts = Object.values(productSales)
                .sort((a, b) => b.quantity - a.quantity)
                .slice(0, 10);

            // By category
            const productCategoryMap: { [key: string]: string } = {};
            prods.forEach((p: Product) => {
                productCategoryMap[p.id] = p.category_id;
            });

            const categorySales: { [key: string]: number } = {};
            orderItems.forEach((item: OrderItem) => {
                const catId = productCategoryMap[item.product_id] || 'uncategorized';
                categorySales[catId] = (categorySales[catId] || 0) + item.total;
            });

            const byCategory = cats.map((cat: Category) => ({
                categoryId: cat.id,
                name: cat.name,
                icon: cat.icon,
                color: cat.color,
                total: categorySales[cat.id] || 0
            })).filter(c => c.total > 0).sort((a, b) => b.total - a.total);

            setStats({
                totalRevenue,
                totalOrders: orders.length,
                averageTicket: paidOrdersCount > 0 ? totalRevenue / paidOrdersCount : 0,
                previousRevenue,
                previousOrders: prevOrders.length,
                deliveryCount,
                pickupCount,
                byPaymentMethod,
                byStatus,
                byHour,
                byDay,
                topProducts,
                byCategory,
                comparisonRevenue,
                comparisonOrders: comparisonOrdersCount,
                comparisonByDay
            });
        } catch (error) {
            console.error('Error fetching report data:', error);
            toast.error('Erro ao carregar dados do relatório');
        } finally {
            setLoading(false);
        }
    };



    const getPercentChange = (current: number, previous: number) => {
        if (previous === 0) return current > 0 ? 100 : 0;
        return ((current - previous) / previous) * 100;
    };

    const revenueChange = getPercentChange(stats.totalRevenue, stats.previousRevenue);
    const ordersChange = getPercentChange(stats.totalOrders, stats.previousOrders);

    const getPaymentMethodLabel = (method: string) => {
        const labels: Record<string, string> = {
            money: 'Dinheiro',
            pix: 'PIX',
            credit: 'Crédito',
            debit: 'Débito'
        };
        return labels[method] || method;
    };

    const getStatusLabel = (status: string) => {
        const labels: Record<string, string> = {
            pending: 'Aguardando',
            preparing: 'Preparando',
            ready: 'Pronto',
            delivering: 'Entregando',
            delivered: 'Entregue',
            cancelled: 'Cancelado'
        };
        return labels[status] || status;
    };

    const getComparisonLabel = (type: ComparisonType) => {
        const labels: Record<ComparisonType, string> = {
            previous: 'Período anterior',
            lastWeek: 'Semana passada',
            lastMonth: 'Mês passado',
            lastYear: 'Ano passado'
        };
        return labels[type];
    };

    // Prepare chart data
    const dailySalesData = useMemo(() => {
        const days = Object.entries(stats.byDay)
            .map(([day, total]) => ({
                day,
                date: new Date(day + 'T12:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
                atual: total,
                comparacao: stats.comparisonByDay[day] || 0
            }))
            .sort((a, b) => a.day.localeCompare(b.day));
        return days;
    }, [stats.byDay, stats.comparisonByDay]);

    const hourlyData = useMemo(() => {
        const hours = [];
        for (let i = 0; i < 24; i++) {
            hours.push({
                hour: `${i.toString().padStart(2, '0')}:00`,
                pedidos: stats.byHour[i] || 0
            });
        }
        return hours;
    }, [stats.byHour]);

    const paymentData = useMemo(() => {
        return Object.entries(stats.byPaymentMethod).map(([method, total]) => ({
            name: getPaymentMethodLabel(method),
            value: total,
            color: PAYMENT_COLORS[method] || '#6c5ce7'
        }));
    }, [stats.byPaymentMethod]);

    const categoryData = useMemo(() => {
        return stats.byCategory.map(cat => ({
            name: cat.name,
            value: cat.total,
            color: cat.color
        }));
    }, [stats.byCategory]);

    const deliveryData = useMemo(() => {
        return [
            { name: 'Entrega', value: stats.deliveryCount, color: '#ff6b35' },
            { name: 'Balcão', value: stats.pickupCount, color: '#00b894' }
        ];
    }, [stats.deliveryCount, stats.pickupCount]);

    const topProductsData = useMemo(() => {
        return stats.topProducts.slice(0, 5).map(p => ({
            name: p.name.length > 15 ? p.name.substring(0, 15) + '...' : p.name,
            quantidade: p.quantity,
            receita: p.revenue
        }));
    }, [stats.topProducts]);

    const getPeakHours = () => {
        const hours = Object.entries(stats.byHour)
            .map(([hour, count]) => ({ hour: parseInt(hour), count }))
            .sort((a, b) => b.count - a.count)
            .slice(0, 3);
        return hours;
    };

    const handleExportPDF = () => {
        window.print();
    };

    const handleExportCSV = () => {
        // Build CSV Content
        const lines: string[] = [];
        lines.push(`Relatório Gerencial - ${userSettings?.app_name || 'Ligeirinho Hotdog'}`);
        lines.push(`Período: ${periodLabels[period]}`);

        lines.push(`Gerado em: ${new Date().toLocaleString('pt-BR')}`);
        lines.push('');

        // Resumo Geral
        lines.push('RESUMO GERAL');
        lines.push('Métrica;Valor');
        lines.push(`Receita Total;${formatCurrency(stats.totalRevenue)}`);
        lines.push(`Total de Pedidos;${stats.totalOrders}`);
        lines.push(`Ticket Médio;${formatCurrency(stats.averageTicket)}`);
        lines.push('');

        // Formas de Pagamento
        lines.push('FORMAS DE PAGAMENTO');
        lines.push('Método;Valor');
        Object.entries(stats.byPaymentMethod).forEach(([method, total]) => {
            lines.push(`${getPaymentMethodLabel(method)};${formatCurrency(total)}`);
        });
        lines.push('');

        // Status
        lines.push('DISTRIBUIÇÃO DE STATUS');
        lines.push('Status;Quantidade');
        Object.entries(stats.byStatus).forEach(([status, count]) => {
            lines.push(`${getStatusLabel(status)};${count}`);
        });
        lines.push('');

        // Top Produtos
        lines.push('TOP PRODUTOS');
        lines.push('Produto;Quantidade;Receita');
        stats.topProducts.forEach(p => {
            lines.push(`${p.name};${p.quantity};${formatCurrency(p.revenue)}`);
        });

        // Trigger Download
        const csvContent = lines.join('\n');
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.setAttribute('href', url);
        link.setAttribute('download', `relatorio_gerencial_${period}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const periodLabels: Record<PeriodType, string> = {
        today: 'Hoje',
        week: 'Esta Semana',
        month: 'Este Mês',
        '30days': 'Últimos 30 dias',
        custom: 'Personalizado'
    };

    // Custom tooltip for charts
    const CustomTooltip = ({ active, payload, label }: { active?: boolean; payload?: Array<{ value: number; name: string; color: string }>; label?: string }) => {
        if (active && payload && payload.length) {
            return (
                <div className={styles.chartTooltip}>
                    <p className={styles.tooltipLabel}>{label}</p>
                    {payload.map((entry, index) => (
                        <p key={index} className={styles.chartTooltipText} style={{ color: entry.color }}>
                            {entry.name}: {entry.name.includes('receita') || entry.name === 'atual' ? formatCurrency(entry.value) : entry.value}
                        </p>
                    ))}
                </div>
            );
        }
        return null;
    };

    // Check if user has access to reports
    if (!canAccess('reports')) {
        return (
            <UpgradePrompt
                feature="Relatórios"
                requiredPlan="Avançado"
                currentPlan={plan}
                fullPage
            />
        );
    }

    return (
        <div className="max-w-[1400px] mx-auto">
            {/* Header */}
            <div className="flex items-start justify-between mb-8 gap-5 max-md:flex-col">
                <div>
                    <h1 className="text-[2rem] font-bold mb-2">Relatórios</h1>
                    <p className={styles.subtitle}>Análise detalhada do desempenho do seu negócio</p>
                </div>

                <div className={styles.headerActions}>
                    {canAccess('exportPdf') && isClient && (
                        <Button leftIcon={<FiFileText />} onClick={handleExportCSV} variant="outline">
                            Exportar CSV
                        </Button>
                    )}

                    {canAccess('exportPdf') && isClient && (
                        <PDFDownloadLink
                            document={
                                <RelatorioPDFCompleto
                                    reportData={{
                                        businessName: userSettings?.app_name || 'Cola Aí',
                                        periodoSelecionado: periodLabels[period],
                                        secoes: [
                                            {
                                                titulo: 'Resumo Geral',
                                                tipo: 'kpi' as const,
                                                dados: [
                                                    { label: 'Receita Total', value: formatCurrency(stats.totalRevenue) },
                                                    { label: 'Total Pedidos', value: String(stats.totalOrders) },
                                                    { label: 'Ticket Médio', value: formatCurrency(stats.averageTicket) }
                                                ]
                                            },
                                            {
                                                titulo: 'Formas de Pagamento',
                                                tipo: 'kpi' as const,
                                                dados: Object.entries(stats.byPaymentMethod).map(([method, total]) => ({
                                                    label: getPaymentMethodLabel(method),
                                                    value: formatCurrency(total)
                                                }))
                                            },
                                            {
                                                titulo: 'Top Produtos',
                                                tipo: 'tabela' as const,
                                                dados: stats.topProducts.map(p => ({
                                                    produto: p.name,
                                                    qtd: p.quantity,
                                                    total: formatCurrency(p.revenue)
                                                })),
                                                colunas: [
                                                    { header: 'Produto', key: 'produto', width: '50%' },
                                                    { header: 'Qtd.', key: 'qtd', width: '20%' },
                                                    { header: 'Total', key: 'total', width: '30%' }
                                                ]
                                            },
                                            {
                                                titulo: 'Distribuição de Status',
                                                tipo: 'lista' as const,
                                                dados: Object.entries(stats.byStatus).map(([status, count]) => ({
                                                    label: getStatusLabel(status),
                                                    value: String(count)
                                                }))
                                            }
                                        ],
                                        comparacao: {
                                            periodo: getComparisonLabel(comparison),
                                            dados: {
                                                'Receita': formatCurrency(stats.comparisonRevenue),
                                                'Pedidos': String(stats.comparisonOrders)
                                            }
                                        }
                                    }}
                                />
                            }
                            fileName={`relatorio_${period}.pdf`}
                        >
                            {({ loading }) => (
                                <Button leftIcon={<FiDownload />} isLoading={loading}>
                                    {loading ? 'Preparando...' : 'Exportar PDF'}
                                </Button>
                            )}
                        </PDFDownloadLink>
                    )}
                </div>
            </div>

            {/* Period Selector */}
            <div className={styles.periodSelector}>
                <div className={styles.periodTabs}>
                    {(['today', 'week', 'month', '30days', 'custom'] as PeriodType[]).map((p) => (
                        <button
                            key={p}
                            className={`${styles.periodTab} ${period === p ? styles.active : ''}`}
                            onClick={() => setPeriod(p)}
                        >
                            {periodLabels[p]}
                        </button>
                    ))}
                </div>
                {period === 'custom' && (
                    <div className={styles.customDates}>
                        <div className={styles.dateInputGroup}>
                            <FiCalendar />
                            <input
                                type="date"
                                value={customStartDate}
                                onChange={(e) => setCustomStartDate(e.target.value)}
                                className={styles.dateInput}
                            />
                        </div>
                        <span className={styles.dateSeparator}>até</span>
                        <div className={styles.dateInputGroup}>
                            <FiCalendar />
                            <input
                                type="date"
                                value={customEndDate}
                                onChange={(e) => setCustomEndDate(e.target.value)}
                                className={styles.dateInput}
                            />
                        </div>
                    </div>
                )}
            </div>

            {/* Comparison Selector */}
            <div className={styles.comparisonSelector}>
                <span className={styles.comparisonLabel}>
                    <FiActivity /> Comparar com:
                </span>
                <div className={styles.comparisonTabs}>
                    {(['previous', 'lastWeek', 'lastMonth', 'lastYear'] as ComparisonType[]).map((c) => (
                        <button
                            key={c}
                            className={`${styles.comparisonTab} ${comparison === c ? styles.active : ''}`}
                            onClick={() => setComparison(c)}
                        >
                            {getComparisonLabel(c)}
                        </button>
                    ))}
                </div>
            </div>

            {loading ? (
                <div className={styles.loadingGrid}>
                    {[1, 2, 3, 4].map(i => (
                        <div key={i} className={`${styles.loadingCard} skeleton`} />
                    ))}
                </div>
            ) : (
                <>
                    {/* Main Stats */}
                    <div className={styles.statsGrid}>
                        <Card className={styles.statCard}>
                            <div className={styles.statIconWrapper} style={{ background: 'rgba(0, 184, 148, 0.1)' }}>
                                <FiDollarSign style={{ color: 'var(--accent)' }} />
                            </div>
                            <div className={styles.statContent}>
                                <span className={styles.statLabel}>Receita Total</span>
                                <span className={styles.statValue}>{formatCurrency(stats.totalRevenue)}</span>
                                <div className={`${styles.statChange} ${revenueChange >= 0 ? styles.positive : styles.negative}`}>
                                    {revenueChange >= 0 ? <FiTrendingUp /> : <FiTrendingDown />}
                                    <span>{Math.abs(revenueChange).toFixed(1)}%</span>
                                    <span className={styles.changeLabel}>vs período anterior</span>
                                </div>
                            </div>
                        </Card>

                        <Card className={styles.statCard}>
                            <div className={styles.statIconWrapper} style={{ background: 'rgba(255, 107, 53, 0.1)' }}>
                                <FiShoppingBag style={{ color: 'var(--primary)' }} />
                            </div>
                            <div className={styles.statContent}>
                                <span className={styles.statLabel}>Total de Pedidos</span>
                                <span className={styles.statValue}>{stats.totalOrders}</span>
                                <div className={`${styles.statChange} ${ordersChange >= 0 ? styles.positive : styles.negative}`}>
                                    {ordersChange >= 0 ? <FiTrendingUp /> : <FiTrendingDown />}
                                    <span>{Math.abs(ordersChange).toFixed(1)}%</span>
                                    <span className={styles.changeLabel}>vs período anterior</span>
                                </div>
                            </div>
                        </Card>

                        <Card className={styles.statCard}>
                            <div className={styles.statIconWrapper} style={{ background: 'rgba(9, 132, 227, 0.1)' }}>
                                <FiBarChart2 style={{ color: 'var(--info)' }} />
                            </div>
                            <div className={styles.statContent}>
