import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/utils/supabase/server';
import { sendTelegramNotification, formatPixTelegramMessage } from '@/lib/telegram';

export async function POST(req: NextRequest) {
    try {
        const { planType, amount, billingPeriod } = await req.json();

        if (!planType || !amount) {
            return new NextResponse('Missing planType or amount', { status: 400 });
        }

        const supabase = await createClient();
        const { data: { user } } = await supabase.auth.getUser();

        if (!user || !user.email) {
            return new NextResponse('Unauthorized', { status: 401 });
        }

        console.log('[PIX Notification] Manual notification from user:', user.id, 'Plan:', planType);

        // Format and send telegram message
        const telegramMessage = formatPixTelegramMessage({
            planType: `${planType} (${billingPeriod === 'annual' ? 'Anual' : 'Mensal'})`,
            amount: amount,
            userEmail: user.email,
            subscriptionId: `MANUAL-${user.id.substring(0, 8)}`
        });

        const result = await sendTelegramNotification(telegramMessage);

        if (result.success) {
            return NextResponse.json({
                success: true,
                message: 'Notificação enviada com sucesso ao administrador.'
            });
        } else {
            return NextResponse.json({
                success: false,
                message: 'Falha ao enviar notificação.'
            }, { status: 500 });
        }

    } catch (error: any) {
        console.error('[PIX Notification] Error:', error);
        return new NextResponse(`Internal Error: ${error.message}`, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/utils/supabase/server';
import { stripe } from '@/lib/stripe';
import { supabaseAdmin } from '@/lib/supabase-admin';

// Map Stripe subscription status to Supabase status
function mapStripeStatus(stripeStatus: string): string {
    switch (stripeStatus) {
        case 'trialing':
            return 'trial';
        case 'active':
            return 'active';
        case 'canceled':
        case 'cancelled':
            return 'cancelled';
        case 'past_due':
        case 'unpaid':
            return 'expired';
        default:
            return stripeStatus;
    }
}

// Derive plan type from Stripe price ID
function getPlanTypeFromPriceId(priceId: string): string {
    if (priceId === process.env.NEXT_PUBLIC_STRIPE_PRICE_BASIC) return 'Basico';
    if (priceId === process.env.NEXT_PUBLIC_STRIPE_PRICE_PROFESSIONAL) return 'Avançado';
    if (priceId === process.env.NEXT_PUBLIC_STRIPE_PRICE_ENTERPRISE) return 'Profissional';
    return 'Basico'; // Default fallback
}

export async function POST(req: NextRequest) {
    try {
        const supabase = await createClient();
        const {
            data: { user },
        } = await supabase.auth.getUser();

        if (!user) {
            return new NextResponse('Unauthorized', { status: 401 });
        }

        console.log('[Sync] Starting sync for user:', user.id);

        // Get local subscription to find stripe_customer_id
        const { data: subscription } = await supabaseAdmin
            .from('subscriptions')
            .select('*')
            .eq('user_id', user.id)
            .maybeSingle(); // Use maybeSingle to handle no results gracefully

        // First try to get subscriptions from Stripe using customer ID
        let stripeCustomerId = subscription?.stripe_customer_id;

        // If no customer ID in local DB, try to find by email in Stripe
        if (!stripeCustomerId) {
            const customers = await stripe.customers.list({
                email: user.email,
                limit: 1
            });
            if (customers.data.length > 0) {
                stripeCustomerId = customers.data[0].id;
            }
        }

        if (!stripeCustomerId) {
            console.log('[Sync] No Stripe Customer ID found for user:', user.id);
            return new NextResponse('No Stripe Customer ID found', { status: 404 });
        }

        console.log('[Sync] Found Stripe customer:', stripeCustomerId);

        // List subscriptions from Stripe - prioritize active and trialing
        const stripeSubscriptions = await stripe.subscriptions.list({
            customer: stripeCustomerId,
            limit: 10, // Get more to find active one
        });

        console.log('[Sync] Found', stripeSubscriptions.data.length, 'subscriptions in Stripe');

        // Find the best subscription (prioritize active > trialing > others)
        let stripeSub = stripeSubscriptions.data.find(s => s.status === 'active');
        if (!stripeSub) {
            stripeSub = stripeSubscriptions.data.find(s => s.status === 'trialing');
        }
        if (!stripeSub && stripeSubscriptions.data.length > 0) {
            stripeSub = stripeSubscriptions.data[0]; // Fall back to most recent
        }

        if (!stripeSub) {
            console.log('[Sync] No subscriptions found in Stripe for customer:', stripeCustomerId);
            return NextResponse.json({ message: 'No subscriptions found in Stripe' });
        }

        console.log('[Sync] Using subscription:', stripeSub.id, 'status:', stripeSub.status);

        // Map Price ID to Plan Type
        const priceId = stripeSub.items.data[0].price.id;
        const planType = getPlanTypeFromPriceId(priceId);
        const mappedStatus = mapStripeStatus(stripeSub.status);

        console.log('[Sync] Plan type:', planType, 'Status:', mappedStatus);

        // Get the next invoice date from Stripe (this is the exact date of the next charge)
        let nextInvoiceDate: string | null = null;
        try {
            const upcomingInvoice = await stripe.invoices.createPreview({
                customer: stripeCustomerId,
                subscription: stripeSub.id
            });
            if (upcomingInvoice.next_payment_attempt) {
                nextInvoiceDate = new Date(upcomingInvoice.next_payment_attempt * 1000).toISOString();
            } else if (upcomingInvoice.created) {
                nextInvoiceDate = new Date(upcomingInvoice.created * 1000 + 30 * 24 * 60 * 60 * 1000).toISOString();
            }
            console.log('[Sync] Next invoice date from Stripe:', nextInvoiceDate);
        } catch (error) {
            console.log('[Sync] No upcoming invoice found, using current_period_end');
            nextInvoiceDate = new Date(stripeSub.current_period_end * 1000).toISOString();
        }

        // Upsert to handle both insert and update cases
        const { error } = await supabaseAdmin
            .from('subscriptions')
            .upsert({
                user_id: user.id,
                stripe_customer_id: stripeCustomerId,
                stripe_subscription_id: stripeSub.id,
                stripe_price_id: priceId,
                status: mappedStatus,
                plan_type: planType,
                trial_ends_at: stripeSub.trial_end ? new Date(stripeSub.trial_end * 1000).toISOString() : null,
                current_period_start: stripeSub.current_period_start ? new Date(stripeSub.current_period_start * 1000).toISOString() : new Date().toISOString(),
                current_period_end: stripeSub.current_period_end ? new Date(stripeSub.current_period_end * 1000).toISOString() : new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString(),
                stripe_current_period_end: nextInvoiceDate || (stripeSub.current_period_end ? new Date(stripeSub.current_period_end * 1000).toISOString() : new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString()),
                billing_period: 'monthly'
            }, { onConflict: 'user_id' });

        if (error) {
            console.error('[Sync] Error syncing subscription:', error);
            return NextResponse.json({
                error: 'Failed to update subscription',
                details: error.message,
                code: error.code
            }, { status: 500 });
        }

        console.log('[Sync] Successfully synced subscription');

        return NextResponse.json({
            message: 'Subscription synced successfully',
            status: mappedStatus,
            plan_type: planType,
            current_period_end: nextInvoiceDate || new Date(stripeSub.current_period_end * 1000).toISOString()
        });

    } catch (error) {
        console.error('[Sync] Sync error:', error);
        return new NextResponse('Internal Error', { status: 500 });
    }
}

'use client';

import React, { useState, useMemo } from 'react';
import { cn } from '@/lib/utils';
import {
    FiSearch,
    FiChevronUp,
    FiChevronDown,
    FiChevronLeft,
    FiChevronRight,
    FiMoreVertical,
    FiCheck
} from 'react-icons/fi';

export interface Column<T> {
    key: keyof T | string;
    header: string;
    sortable?: boolean;
    width?: string;
    render?: (value: unknown, row: T) => React.ReactNode;
}

export interface DataTableProps<T> {
    columns: Column<T>[];
    data: T[];
    keyField: keyof T;
    searchable?: boolean;
    searchPlaceholder?: string;
    selectable?: boolean;
    onRowClick?: (row: T) => void;
    onSelectionChange?: (selected: T[]) => void;
    actions?: (row: T) => React.ReactNode;
    pageSize?: number;
    loading?: boolean;
    emptyMessage?: string;
}

export default function DataTable<T extends object>({
    columns,
    data,
    keyField,
    searchable = true,
    searchPlaceholder = 'Buscar...',
    selectable = false,
    onRowClick,
    onSelectionChange,
    actions,
    pageSize = 10,
    loading = false,
    emptyMessage = 'Nenhum dado encontrado',
}: DataTableProps<T>) {
    const [search, setSearch] = useState('');
    const [sortKey, setSortKey] = useState<keyof T | string | null>(null);
    const [sortDir, setSortDir] = useState<'asc' | 'desc'>('asc');
    const [selected, setSelected] = useState<Set<unknown>>(new Set());
    const [currentPage, setCurrentPage] = useState(1);

    // Filter data by search
    const filteredData = useMemo(() => {
        if (!search.trim()) return data;
        const lowerSearch = search.toLowerCase();
        return data.filter((row) =>
            Object.values(row).some(
                (val) => String(val).toLowerCase().includes(lowerSearch)
            )
        );
    }, [data, search]);

    // Sort data
    const sortedData = useMemo(() => {
        if (!sortKey) return filteredData;
        return [...filteredData].sort((a, b) => {
            const aVal = a[sortKey as keyof T];
            const bVal = b[sortKey as keyof T];
            if (aVal === bVal) return 0;
            if (aVal === null || aVal === undefined) return 1;
            if (bVal === null || bVal === undefined) return -1;
            const comparison = aVal < bVal ? -1 : 1;
            return sortDir === 'asc' ? comparison : -comparison;
        });
    }, [filteredData, sortKey, sortDir]);

    // Paginate data
    const paginatedData = useMemo(() => {
        const start = (currentPage - 1) * pageSize;
        return sortedData.slice(start, start + pageSize);
    }, [sortedData, currentPage, pageSize]);

    const totalPages = Math.ceil(sortedData.length / pageSize);

    const handleSort = (key: keyof T | string) => {
        if (sortKey === key) {
            setSortDir(sortDir === 'asc' ? 'desc' : 'asc');
        } else {
            setSortKey(key);
            setSortDir('asc');
        }
    };

    const toggleSelectAll = () => {
        if (selected.size === paginatedData.length) {
            setSelected(new Set());
            onSelectionChange?.([]);
        } else {
            const newSelected = new Set(paginatedData.map((row) => row[keyField]));
            setSelected(newSelected);
            onSelectionChange?.(paginatedData);
        }
    };

    const toggleSelect = (row: T) => {
        const key = row[keyField];
        const newSelected = new Set(selected);
        if (newSelected.has(key)) {
            newSelected.delete(key);
        } else {
            newSelected.add(key);
        }
        setSelected(newSelected);
        onSelectionChange?.(data.filter((r) => newSelected.has(r[keyField])));
    };

    const getValue = (row: T, key: keyof T | string): unknown => {
        if (typeof key === 'string' && key.includes('.')) {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            return key.split('.').reduce((obj: any, k: string) => obj?.[k], row as any);
        }
        return row[key as keyof T];
    };

    if (loading) {
        return (
            <div className="bg-gray-800/50 border border-gray-700 rounded-xl overflow-hidden">
                <div className="p-4 border-b border-gray-700">
                    <div className="h-10 bg-gray-700 rounded-lg animate-pulse w-72" />
                </div>
                <div className="divide-y divide-gray-700">
                    {Array.from({ length: 5 }).map((_, i) => (
                        <div key={i} className="p-4 flex gap-4">
                            {Array.from({ length: columns.length }).map((_, j) => (
                                <div key={j} className="h-5 bg-gray-700 rounded animate-pulse flex-1" />
                            ))}
                        </div>
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="bg-gray-800/50 border border-gray-700 rounded-xl overflow-hidden">
            {/* Search Bar */}
            {searchable && (
                <div className="p-4 border-b border-gray-700">
                    <div className="relative">
                        <FiSearch className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                        <input
                            type="text"
                            value={search}
                            onChange={(e) => {
                                setSearch(e.target.value);
                                setCurrentPage(1);
                            }}
                            placeholder={searchPlaceholder}
                            className="w-full max-w-sm pl-10 pr-4 py-2.5 bg-gray-900 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:outline-none focus:border-orange-500 focus:ring-1 focus:ring-orange-500"
                        />
                    </div>
                </div>
            )}

            {/* Table */}
            <div className="overflow-x-auto">
                <table className="w-full">
                    <thead>
                        <tr className="bg-gray-900/50">
                            {selectable && (
                                <th className="w-12 px-4 py-3">
                                    <button
                                        onClick={toggleSelectAll}
                                        className={cn(
                                            "w-5 h-5 rounded border flex items-center justify-center transition-colors",
                                            selected.size === paginatedData.length && paginatedData.length > 0
                                                ? "bg-orange-500 border-orange-500"
                                                : "border-gray-600 hover:border-gray-500"
                                        )}
                                    >
                                        {selected.size === paginatedData.length && paginatedData.length > 0 && (
                                            <FiCheck className="text-white" size={14} />
                                        )}
                                    </button>
                                </th>
                            )}
                            {columns.map((col) => (
                                <th
                                    key={String(col.key)}
                                    className={cn(
                                        "px-4 py-3 text-left text-xs font-semibold text-gray-400 uppercase tracking-wider",
                                        col.sortable && "cursor-pointer hover:text-white select-none"
                                    )}
                                    style={{ width: col.width }}
                                    onClick={() => col.sortable && handleSort(col.key)}
                                >
                                    <div className="flex items-center gap-2">
                                        {col.header}
                                        {col.sortable && sortKey === col.key && (
                                            sortDir === 'asc' ? <FiChevronUp size={14} /> : <FiChevronDown size={14} />
                                        )}
                                    </div>
                                </th>
                            ))}
                            {actions && <th className="w-12 px-4 py-3" />}
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-700/50">
                        {paginatedData.length === 0 ? (
                            <tr>
                                <td
                                    colSpan={columns.length + (selectable ? 1 : 0) + (actions ? 1 : 0)}
                                    className="px-4 py-12 text-center text-gray-500"
                                >
                                    {emptyMessage}
                                </td>
                            </tr>
                        ) : (
                            paginatedData.map((row) => {
                                const rowKey = row[keyField] as string;
                                const isSelected = selected.has(rowKey);
                                return (
                                    <tr
                                        key={rowKey}
                                        onClick={() => onRowClick?.(row)}
                                        className={cn(
                                            "transition-colors",
                                            onRowClick && "cursor-pointer",
                                            isSelected ? "bg-orange-500/10" : "hover:bg-gray-700/30"
                                        )}
                                    >
                                        {selectable && (
                                            <td className="px-4 py-3">
                                                <button
                                                    onClick={(e) => {
                                                        e.stopPropagation();
                                                        toggleSelect(row);
                                                    }}
                                                    className={cn(
                                                        "w-5 h-5 rounded border flex items-center justify-center transition-colors",
                                                        isSelected
                                                            ? "bg-orange-500 border-orange-500"
                                                            : "border-gray-600 hover:border-gray-500"
                                                    )}
                                                >
                                                    {isSelected && <FiCheck className="text-white" size={14} />}
                                                </button>
                                            </td>
                                        )}
                                        {columns.map((col) => {
                                            const value = getValue(row, col.key);
                                            return (
                                                <td key={String(col.key)} className="px-4 py-3 text-sm text-gray-300">
                                                    {col.render ? col.render(value, row) : String(value ?? '-')}
                                                </td>
                                            );
                                        })}
                                        {actions && (
                                            <td className="px-4 py-3">
                                                <div className="flex justify-end">
                                                    {actions(row)}
                                                </div>
                                            </td>
                                        )}
                                    </tr>
                                );
                            })
                        )}
                    </tbody>
                </table>
            </div>

            {/* Pagination */}
            {totalPages > 1 && (
                <div className="p-4 border-t border-gray-700 flex items-center justify-between">
                    <span className="text-sm text-gray-500">
                        Mostrando {((currentPage - 1) * pageSize) + 1} a {Math.min(currentPage * pageSize, sortedData.length)} de {sortedData.length}
                    </span>
                    <div className="flex items-center gap-2">
                        <button
                            onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                            disabled={currentPage === 1}
                            className="p-2 rounded-lg bg-gray-700 text-gray-400 hover:text-white hover:bg-gray-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                        >
                            <FiChevronLeft size={18} />
                        </button>
                        <span className="px-4 py-2 text-sm text-gray-400">
                            {currentPage} / {totalPages}
                        </span>
                        <button
                            onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
                            disabled={currentPage === totalPages}
                            className="p-2 rounded-lg bg-gray-700 text-gray-400 hover:text-white hover:bg-gray-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                        >
                            <FiChevronRight size={18} />
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { FiSearch, FiMessageCircle, FiFilter, FiUser, FiClock, FiShoppingBag } from 'react-icons/fi';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import Input from '@/components/ui/Input';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/lib/supabase';
import { formatCurrency } from '@/hooks/useFormatters';
import { cn } from '@/lib/utils';
import { WhatsappSenderModal } from './WhatsappSenderModal';
import { useCustomersCache, useOrdersCache } from '@/hooks/useDataCache';

export interface CustomerCRM {
    id: string;
    phone: string;
    name: string;
    email: string | null;
    total_points: number;
    total_spent: number;
    total_orders: number;
    created_at: string | null;
    last_order_date?: string | null; // Pode ser mapeado via pedidos
}

export function CustomerListTab() {
    const { customers: rawCustomers, loading: loadingCustomers } = useCustomersCache();
    const { orders: rawOrders, loading: loadingOrders } = useOrdersCache();
    const [searchTerm, setSearchTerm] = useState('');
    const [filterInactive, setFilterInactive] = useState(false);
    const [selectedCustomerIds, setSelectedCustomerIds] = useState<Set<string>>(new Set());
    const [showWhatsappModal, setShowWhatsappModal] = useState(false);

    const loading = loadingCustomers && loadingOrders;

    const customers = React.useMemo(() => {
        const lastOrdersMap = new Map<string, string | null>();
        if (rawOrders) {
            rawOrders.forEach(order => {
                if (order.customer_phone && !lastOrdersMap.has(order.customer_phone)) {
                    lastOrdersMap.set(order.customer_phone, order.created_at);
                }
            });
        }

        return (rawCustomers || []).map(c => ({
            ...c,
            last_order_date: lastOrdersMap.get(c.phone) || c.created_at
        })).sort((a, b) => (b.total_spent || 0) - (a.total_spent || 0));
    }, [rawCustomers, rawOrders]);

    // Lógica de inatividade (mais de 30 dias)
    const isInactive = (dateStr?: string | null) => {
        if (!dateStr) return false;
        const now = new Date();
        const date = new Date(dateStr);
        const diffMs = now.getTime() - date.getTime();
        const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
        return diffDays > 30;
    };

    // Filter
    const filteredCustomers = React.useMemo(() => {
        let result = customers;
        if (searchTerm) {
            const query = searchTerm.toLowerCase();
            const digits = searchTerm.replace(/\D/g, '');
            result = result.filter(c =>
                c.name.toLowerCase().includes(query) ||
                (digits && c.phone.includes(digits))
            );
        }
        if (filterInactive) {
            result = result.filter(c => isInactive(c.last_order_date));
        }
        return result;
    }, [customers, searchTerm, filterInactive]);

    // Seleção
    const toggleSelectAll = () => {
        if (selectedCustomerIds.size === filteredCustomers.length && filteredCustomers.length > 0) {
            setSelectedCustomerIds(new Set());
        } else {
            setSelectedCustomerIds(new Set(filteredCustomers.map(c => c.id)));
        }
    };

    const toggleSelectCustomer = (id: string) => {
        const next = new Set(selectedCustomerIds);
        if (next.has(id)) next.delete(id);
        else next.add(id);
        setSelectedCustomerIds(next);
    };

    const selectedCustomersList = customers.filter(c => selectedCustomerIds.has(c.id));

    // Utils visuais
    const formatDate = (dateStr?: string | null) => {
        if (!dateStr) return 'Nunca';
        return new Intl.DateTimeFormat('pt-BR', { day: '2-digit', month: 'short', year: 'numeric' }).format(new Date(dateStr));
    };

    return (
        <div className="flex flex-col gap-6">
            <Card className="flex items-center justify-between gap-4 flex-wrap p-4!">
                <div className="flex items-start sm:items-center flex-col sm:flex-row gap-3 w-full lg:w-auto flex-1">
                    <Input
                        placeholder="Buscar por nome ou telefone..."
                        leftIcon={<FiSearch />}
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="flex-1 w-full sm:w-auto"
                    />
                    <button
                        className={cn(
                            "flex items-center gap-2 px-4 py-2 bg-bg-tertiary border border-border rounded-md text-sm font-medium transition-all",
                            filterInactive && "bg-accent/10 border-accent text-accent"
                        )}
                        onClick={() => setFilterInactive(!filterInactive)}
                    >
                        <FiFilter /> Inativos (+30 dias)
                    </button>
                </div>
                <div className="flex flex-col sm:flex-row items-stretch sm:items-center justify-between sm:justify-start gap-3 w-full lg:w-auto">
                    <span className="text-sm text-text-muted text-center sm:text-left">
                        {selectedCustomerIds.size} selecionado(s)
                    </span>
                    <Button
                        leftIcon={<FiMessageCircle />}
                        variant={selectedCustomerIds.size > 0 ? "primary" : "outline"}
                        disabled={selectedCustomerIds.size === 0}
                        onClick={() => setShowWhatsappModal(true)}
                        className="w-full sm:w-auto"
                    >
                        Disparar WhatsApp
                    </Button>
                </div>
            </Card>

            <Card className="overflow-hidden p-0!">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-bg-tertiary border-b border-border">
                                <th className="p-4 w-[50px] whitespace-nowrap">
                                    <input
                                        type="checkbox"
                                        className="w-[18px] h-[18px] cursor-pointer accent-primary"
                                        checked={selectedCustomerIds.size > 0 && selectedCustomerIds.size === filteredCustomers.length}
                                        onChange={toggleSelectAll}
                                    />
                                </th>
                                <th className="p-4 text-sm font-semibold text-text-secondary whitespace-nowrap">Cliente</th>
                                <th className="p-4 text-sm font-semibold text-text-secondary whitespace-nowrap">Telefone</th>
                                <th className="p-4 text-sm font-semibold text-text-secondary whitespace-nowrap hidden sm:table-cell">Última Compra</th>
                                <th className="p-4 text-sm font-semibold text-text-secondary whitespace-nowrap hidden md:table-cell">Total Pedidos</th>
                                <th className="p-4 text-sm font-semibold text-text-secondary whitespace-nowrap hidden sm:table-cell">Gastos</th>
                                <th className="p-4 text-center text-sm font-semibold text-text-secondary whitespace-nowrap">Status</th>
                            </tr>
                        </thead>
                        <tbody>
                            {loading ? (
                                <tr>
                                    <td colSpan={7} className="p-8 text-center text-text-muted">Carregando clientes...</td>
                                </tr>
                            ) : filteredCustomers.length === 0 ? (
                                <tr>
                                    <td colSpan={7} className="p-8 text-center text-text-muted">Nenhum cliente encontrado.</td>
                                </tr>
                            ) : (
                                filteredCustomers.map(customer => {
                                    const inactive = isInactive(customer.last_order_date);
                                    return (
                                        <tr key={customer.id} className={cn(
                                            "border-b border-border hover:bg-bg-tertiary/50 transition-colors",
                                            selectedCustomerIds.has(customer.id) && "bg-primary/5"
                                        )}>
                                            <td className="p-4 whitespace-nowrap">
                                                <input
                                                    type="checkbox"
                                                    className="w-[18px] h-[18px] cursor-pointer accent-primary"
                                                    checked={selectedCustomerIds.has(customer.id)}
                                                    onChange={() => toggleSelectCustomer(customer.id)}
                                                />
                                            </td>
                                            <td className="p-4 whitespace-nowrap">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-8 h-8 rounded-full bg-border flex items-center justify-center text-text-secondary shrink-0">
                                                        <FiUser />
                                                    </div>
                                                    <span className="font-medium text-text-primary">{customer.name}</span>
                                                </div>
                                            </td>
                                            <td className="p-4 text-text-secondary whitespace-nowrap">{customer.phone}</td>
                                            <td className="p-4 text-text-secondary whitespace-nowrap hidden sm:table-cell">
                                                <div className="flex items-center gap-2">
                                                    <FiClock className={inactive ? "text-error" : "text-text-muted"} />
                                                    <span className={inactive ? "text-error" : ""}>{formatDate(customer.last_order_date)}</span>
                                                </div>
                                            </td>
                                            <td className="p-4 text-text-secondary whitespace-nowrap hidden md:table-cell">
                                                <div className="flex items-center gap-2">
                                                    <FiShoppingBag className="text-primary hidden md:block" /> {customer.total_orders || 0}
                                                </div>
                                            </td>
                                            <td className="p-4 font-semibold text-[#27ae60] whitespace-nowrap hidden sm:table-cell">
                                                {formatCurrency(customer.total_spent || 0)}
                                            </td>
                                            <td className="p-4 text-center whitespace-nowrap">
                                                {inactive ? (
                                                    <span className="px-2 py-1 bg-error/10 text-error rounded-full text-xs font-medium">Inativo</span>
                                                ) : (
                                                    <span className="px-2 py-1 bg-[#27ae60]/10 text-[#27ae60] rounded-full text-xs font-medium">Ativo</span>
                                                )}
                                            </td>
                                        </tr>
                                    )
                                })
                            )}
                        </tbody>
                    </table>
                </div>
            </Card>

            {/* Modal de Disparo (implementado em outro arquivo para organizar) */}
            {showWhatsappModal && (
                <WhatsappSenderModal
                    recipients={selectedCustomersList}
                    onClose={() => setShowWhatsappModal(false)}
                />
            )}
        </div>
    );
}

